static void CheckerReportsNoMatchingCSharpDelegateLambdaBlockReturnOverloadDiagnostics()
{
    WithWorkspace(root =>
    {
        BuildLegacyReferenceDll(root, "Legacy.Tools");
        var manifestPath = WriteManifest(root, """
            [project]
            name = "NoMatchingDelegateLambdaBlockReturnOverload"
            targetFramework = "net48"
            outputType = "library"
            rootNamespace = "Samples.NoMatchingDelegateLambdaBlockReturnOverload"
            generatedOutputRoot = "generated"

            [references]
            paths = ["lib/Legacy.Tools.dll"]
            """);
        WriteFile(root, "src/Main.tysh", """
            namespace Samples.NoMatchingDelegateLambdaBlockReturnOverload

            import { LegacyDelegateOverloads } from "Legacy.Tools"

            export fun broken(): string =
              LegacyDelegateOverloads.RequiresBlockReturnInt("Ada", text => { (text) })
            """);

        var result = TypeSharpChecker.Check(manifestPath);

        AssertTrue(result.HasErrors, "C# delegate lambda block return mismatch should produce diagnostics.");
        var diagnostic = result.Diagnostics.Single(diagnostic => diagnostic.Code == "TS2406");
        AssertEqual("src/Main.tysh", diagnostic.File);
        AssertContains("LegacyDelegateOverloads.RequiresBlockReturnInt", diagnostic.Message);
        AssertContains("matches no overload candidate", diagnostic.Message);
    });
}

