static void CliBuildStopsBeforeEmissionOnUnsupportedTypeSharpClassAndInterfaceMembers()
{
    WithWorkspace(root =>
    {
        var manifestPath = WriteManifest(root, """
            [project]
            name = "UnsupportedClassMembers"
            targetFramework = "net48"
            outputType = "library"
            rootNamespace = "Samples.UnsupportedClassMembers"
            generatedOutputRoot = "generated"
            """);
        WriteFile(root, "src/Main.tysh", """
            namespace Samples.UnsupportedClassMembers

            public class WithBadConstructor(name) {
              public fun Echo(value: string): string = value
            }

            public class WithBadParamsConstructor(params values: string) {
              public fun Echo(value: string): string = value
            }

            public class WithBadProperty {
              public let Name: string { get }
            }

            public class WithBadSetterProperty {
              public let ImmutableName: string = "value" { get set }
            }

            public class WithBadAccessorModifierProperty {
              public let mut MutableName: string = "value" { get private set }
            }

            public class WithBadInstanceValues {
              public let MissingType = "value"

              public let MissingInitializer: string
            }

            public class WithBadStaticValues {
              public static let MissingType = "value"

              public static let MissingInitializer: string
            }

            public class WithBadEvent {
              public event Changed
            }

            public interface IWithBadEvent {
              public event Changed
            }

            public interface IWithBadImmutableSetterProperty {
              public let Name: string { get set }
            }

            public interface IWithBadMutableGetterOnlyProperty {
              public let mut Name: string { get }
            }

            public interface IWithBadInitializerProperty {
              public let Name: string = "value" { get }
            }

            public interface IWithBadAccessorModifierProperty {
              public let Name: string { public get }
            }

            public interface IBad {
              let Name: string
            }
            """);
        using var output = new StringWriter();
        using var error = new StringWriter();

        var exitCode = TypeSharpCli.Run(["build", manifestPath], output, error);

        AssertEqual(1, exitCode);
        var diagnosticText = output.ToString() + error.ToString();
        AssertContains("TS2210", diagnosticText);
        AssertContains("TypeSharp-authored class constructor parameter 'name' must declare an explicit CLR-visible type", diagnosticText);
        AssertContains("TypeSharp-authored class constructor params parameter 'values' must have an array type", diagnosticText);
        AssertContains("TypeSharp-authored class instance properties must declare an initializer", diagnosticText);
        AssertContains("TypeSharp-authored class properties with setters must use mutable `let mut`", diagnosticText);
        AssertContains("TypeSharp-authored class property accessors cannot declare modifiers or custom bodies in this slice", diagnosticText);
        AssertContains("TypeSharp-authored class instance values must declare an explicit CLR-visible type", diagnosticText);
        AssertContains("TypeSharp-authored class instance values must declare an initializer", diagnosticText);
        AssertContains("TypeSharp-authored class static values must declare an explicit CLR-visible type", diagnosticText);
        AssertContains("TypeSharp-authored class static values must declare an initializer", diagnosticText);
        AssertContains("TypeSharp-authored class events must declare an explicit delegate type", diagnosticText);
        AssertContains("TypeSharp-authored interface events must declare an explicit delegate type", diagnosticText);
        AssertContains("TypeSharp-authored interface properties with setters must use mutable `let mut`", diagnosticText);
        AssertContains("TypeSharp-authored mutable interface properties must declare exactly one getter and one setter accessor in this slice", diagnosticText);
        AssertContains("TypeSharp-authored interface properties cannot declare initializers in this slice", diagnosticText);
        AssertContains("TypeSharp-authored interface property accessors cannot declare modifiers or custom bodies in this slice", diagnosticText);
        AssertContains("Interface field declarations are not part of the 1.0 class/interface member subset", diagnosticText);
        AssertFalse(File.Exists(Path.Combine(root, "generated", "src", "Main.g.cs")), "Build should not emit generated C# when unsupported class/interface member diagnostics contain errors.");
        AssertFalse(File.Exists(Path.Combine(root, "generated", "UnsupportedClassMembers.Generated.csproj")), "Build should not emit generated project when unsupported class/interface member diagnostics contain errors.");
        AssertFalse(File.Exists(Path.Combine(root, "generated", "bin", "Debug", "net48", "UnsupportedClassMembers.dll")), "Build should not emit generated assembly when unsupported class/interface member diagnostics contain errors.");
    });
}

static void CliBuildCompilesEnumDeclarationApi()
{
    WithWorkspace(root =>
    {
        var manifestPath = WriteManifest(root, """
            [project]
            name = "EnumDeclarationApi"
            targetFramework = "net48"
            outputType = "library"
            rootNamespace = "Samples.Enums"
            generatedOutputRoot = "generated"
            """);
        WriteFile(root, "src/Main.tysh", """
            namespace Samples.Enums

            import { FlagsAttribute, ObsoleteAttribute } from "System"

            [FlagsAttribute]
            public enum Color : byte {
              Red = 1,
              Crimson = Red,
              [ObsoleteAttribute("Use Blue instead.")]
              Green,
              Blue = 4,
              Purple = Red | Blue
            }

            export fun favorite(): Color =
              Color.Red | Color.Blue

            export fun bluePart(input: Color): Color =
              input & Color.Blue

            export fun toggled(input: Color): Color =
              input ^ Color.Blue

            export fun inverted(input: Color): Color =
              ~input
            """);
        using var output = new StringWriter();
        using var error = new StringWriter();

        var exitCode = TypeSharpCli.Run(["build", manifestPath], output, error);

        AssertEqual(0, exitCode);
        AssertContains("Generated assembly: bin/Debug/net48/EnumDeclarationApi.dll", output.ToString());
        AssertEqual(string.Empty, error.ToString());

        var generatedSource = File.ReadAllText(Path.Combine(root, "generated", "src", "Main.g.cs")).Replace("\r\n", "\n", StringComparison.Ordinal);
        AssertContains("using System;", generatedSource);
        AssertContains("[FlagsAttribute]", generatedSource);
        AssertContains("public enum Color : byte", generatedSource);
        AssertContains("Red = 1", generatedSource);
        AssertContains("Crimson = Red", generatedSource);
        AssertContains("[ObsoleteAttribute(\"Use Blue instead.\")]", generatedSource);
        AssertContains("Blue = 4", generatedSource);
        AssertContains("Purple = Red | Blue", generatedSource);
        AssertContains("return Color.Red | Color.Blue;", generatedSource);
        AssertContains("return input & Color.Blue;", generatedSource);
        AssertContains("return input ^ Color.Blue;", generatedSource);
        AssertContains("return ~input;", generatedSource);

        var generatedAssemblyPath = Path.Combine(root, "generated", "bin", "Debug", "net48", "EnumDeclarationApi.dll");
        AssertTrue(File.Exists(generatedAssemblyPath), "Build should produce generated net48 assembly with enum declaration API.");

        var metadata = TypeSharpMetadataReader.Read(
        [
            new ResolvedReference(
                ResolvedReferenceKind.LocalAssembly,
                "EnumDeclarationApi",
                generatedAssemblyPath,
                generatedAssemblyPath,
                "generated/bin/Debug/net48/EnumDeclarationApi.dll")
        ]);

        AssertFalse(metadata.HasErrors, "Generated enum declaration assembly metadata should be readable.");
        var abiSnapshotText = string.Join("\n", TypeSharpPublicAbiChecker.CreateSnapshot(metadata.Assemblies.Single()).Lines);
        AssertContains("type Samples.Enums.Color", abiSnapshotText);
        AssertContains("  enum underlying byte", abiSnapshotText);
        AssertContains("  enum member Blue = 4", abiSnapshotText);
        AssertContains("  enum member Crimson = 1", abiSnapshotText);
        AssertContains("  enum member Green = 2", abiSnapshotText);
        AssertContains("  enum member Purple = 5", abiSnapshotText);
        AssertContains("  enum member Red = 1", abiSnapshotText);

        var consumerRoot = Path.Combine(root, "Consumer");
        Directory.CreateDirectory(consumerRoot);
        WriteFile(consumerRoot, "EnumConsumer.csproj", """
            <Project Sdk="Microsoft.NET.Sdk">
              <PropertyGroup>
                <TargetFramework>net48</TargetFramework>
                <LangVersion>7.3</LangVersion>
                <ImplicitUsings>false</ImplicitUsings>
                <Nullable>disable</Nullable>
                <AssemblyName>EnumConsumer</AssemblyName>
              </PropertyGroup>
              <ItemGroup>
                <Reference Include="EnumDeclarationApi">
                  <HintPath>../generated/bin/Debug/net48/EnumDeclarationApi.dll</HintPath>
                </Reference>
              </ItemGroup>
            </Project>
            """);
        WriteFile(consumerRoot, "NuGet.config", """
            <?xml version="1.0" encoding="utf-8"?>
            <configuration>
              <packageSources>
                <clear />
              </packageSources>
            </configuration>
            """);
        WriteFile(consumerRoot, "Consumer.cs", """
            using System;

            namespace EnumConsumer
            {
                public static class Consumer
                {
                    public static bool Read()
                    {
                        var enumAttribute = (FlagsAttribute)Attribute.GetCustomAttribute(
                            typeof(Samples.Enums.Color),
                            typeof(FlagsAttribute));
                        var greenAttribute = (ObsoleteAttribute)Attribute.GetCustomAttribute(
                            typeof(Samples.Enums.Color).GetField("Green"),
                            typeof(ObsoleteAttribute));
                        return enumAttribute != null &&
                            greenAttribute.Message == "Use Blue instead." &&
                            Samples.Enums.Module.favorite() == Samples.Enums.Color.Purple &&
                            Samples.Enums.Module.bluePart(Samples.Enums.Color.Purple) == Samples.Enums.Color.Blue &&
                            Samples.Enums.Module.toggled(Samples.Enums.Color.Purple) == Samples.Enums.Color.Red &&
                            Samples.Enums.Module.inverted(Samples.Enums.Color.Blue) == ~Samples.Enums.Color.Blue &&
                            (int)Samples.Enums.Color.Blue == 4 &&
                            (int)Samples.Enums.Color.Purple == 5;
                    }
                }
            }
            """);

        var build = RunProcess("dotnet", "build EnumConsumer.csproj --nologo --verbosity quiet --ignore-failed-sources", consumerRoot);

        AssertTrue(
            build.ExitCode == 0,
            $"C# net48 consumer project should compile against generated enum declaration API.\nSTDOUT:\n{build.StandardOutput}\nSTDERR:\n{build.StandardError}");
    });
}

