                            Samples.ImportedMultiplicativeCompoundAssignment.Module.instanceFloat(13f, 3) == 1f &&
                            Samples.ImportedMultiplicativeCompoundAssignment.Module.instanceDouble(13.0, 3f) == 1.0 &&
