                    }
                }
            }
            """);

        var build = RunProcess("dotnet", "build ImportedMultiplicativeCompoundAssignmentConsumer.csproj --nologo --verbosity quiet --ignore-failed-sources", consumerRoot);

        AssertTrue(
            build.ExitCode == 0,
            $"C# net48 consumer project should compile against generated imported multiplicative compound assignment APIs.\nSTDOUT:\n{build.StandardOutput}\nSTDERR:\n{build.StandardError}");
    });
}

static void CheckerRejectsUnsupportedImportedMultiplicativeCompoundAssignmentMemberTargets()
{
    WithWorkspace(root =>
    {
        BuildLegacyReferenceDll(root, "Legacy.Tools");
        var manifestPath = WriteManifest(root, """
            [project]
            name = "InvalidImportedMultiplicativeCompoundAssignment"
            targetFramework = "net48"
            outputType = "library"
            rootNamespace = "Samples.InvalidImportedMultiplicativeCompoundAssignment"
            generatedOutputRoot = "generated"

            [references]
            paths = ["lib/Legacy.Tools.dll"]
            """);
        WriteFile(root, "src/Main.tysh", """
            namespace Samples.InvalidImportedMultiplicativeCompoundAssignment

            import { LegacyColor, LegacyEvents, LegacyFields } from "Legacy.Tools"

            export fun boolOperand(): int {
              let fields: LegacyFields = LegacyFields()
              fields.MutableFlag *= true
              0
            }

            export fun checkedBoolOperand(): int {
              let fields: LegacyFields = LegacyFields()
              checked(fields.MutableFlag *= true)
              0
            }

            export fun stringOperand(): int {
              let fields: LegacyFields = LegacyFields()
              fields.MutableCode /= "x"
              0
            }

            export fun enumOperand(color: LegacyColor): int {
              let fields: LegacyFields = LegacyFields()
              fields.MutableColor *= color
              0
            }

            export fun nullableOperand(value: int?): int {
              let fields: LegacyFields = LegacyFields()
              fields.MutableCount %= value
              0
            }

            export fun uncheckedNullableOperand(value: int?): int {
              let fields: LegacyFields = LegacyFields()
              unchecked(fields.MutableCount %= value)
              0
            }

            export fun narrowing(value: long): int {
              let fields: LegacyFields = LegacyFields()
              fields.MutableCount *= value
              0
            }

            export fun mixedDecimalFloating(value: double): int {
              let fields: LegacyFields = LegacyFields()
              fields.MutableDecimal *= value
              0
            }

            export fun narrowingFloat(value: double): int {
              let fields: LegacyFields = LegacyFields()
              fields.MutableFloat *= value
              0
            }

            export fun nullableFloat(value: float?): int {
              let fields: LegacyFields = LegacyFields()
              fields.MutableFloat /= value
              0
            }

            export fun readonlyField(): int {
              let fields: LegacyFields = LegacyFields()
              fields.InstanceCode *= "x"
              0
            }

            export fun checkedReadonlyField(): int {
              let fields: LegacyFields = LegacyFields()
              checked(fields.InstanceCode *= "x")
              0
            }

            export fun eventTarget(): int {
              let events: LegacyEvents = LegacyEvents()
              events.Transform *= null
              0
            }

            export fun uncheckedEventTarget(): int {
              let events: LegacyEvents = LegacyEvents()
              unchecked(events.Transform *= null)
              0
            }

            """);

        var result = TypeSharpChecker.Check(manifestPath);
        const string unsupportedImportedMessage = "Multiplicative compound assignment is supported only for mutable local bindings or readable and writable metadata-backed imported C# field/property/indexer targets; indexer targets require a matching public getter and setter plus supported index arguments, and event, unresolved, and TypeSharp-owned targets are not supported.";

        AssertTrue(result.HasErrors, "Unsupported imported C# multiplicative compound assignment member targets should produce diagnostics.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'bool' and 'bool'."),
            "Imported bool member target should reject multiplicative operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '/=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'string' and 'string'."),
            "Imported string member target should reject multiplicative operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2217" &&
                diagnostic.Message.Contains("Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type", StringComparison.Ordinal) &&
                diagnostic.Message.Contains("LegacyColor", StringComparison.Ordinal)),
            "Imported enum member target should reject multiplicative operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '%=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'int' and 'int?'."),
            "Imported member target should reject nullable multiplicative operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Cannot assign multiplicative compound assignment result of type 'long' to 'int'."),
            "Imported member target should reject multiplicative results that cannot be assigned back.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'decimal' and 'double'."),
            "Imported decimal member target should reject mixed decimal and floating-point operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Cannot assign multiplicative compound assignment result of type 'double' to 'float'."),
            "Imported float member target should reject floating-point results that cannot be assigned back.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '/=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'float' and 'float?'."),
            "Imported float member target should reject nullable floating-point operands.");
        AssertTrue(
            result.Diagnostics.Count(diagnostic =>
                diagnostic.Code == "TS2216" &&
                diagnostic.Message == unsupportedImportedMessage) >= 2,
            "Readonly field and event multiplicative targets should remain rejected before emission.");
    });
}

static void CliBuildCompilesImportedMultiplicativeCompoundAssignmentIndexerTargets()
{
    WithWorkspace(root =>
    {
        BuildLegacyReferenceDll(root, "Legacy.Tools");
        var manifestPath = WriteManifest(root, """
            [project]
            name = "ImportedMultiplicativeCompoundAssignmentIndexerApi"
            targetFramework = "net48"
            outputType = "library"
            rootNamespace = "Samples.ImportedMultiplicativeCompoundAssignmentIndexers"
            generatedOutputRoot = "generated"

            [references]
            paths = ["lib/Legacy.Tools.dll"]
            """);
        WriteFile(root, "src/Main.tysh", """
            namespace Samples.ImportedMultiplicativeCompoundAssignmentIndexers

            import { LegacyDecimalIndexer, LegacyDoubleIndexer, LegacyFloatIndexer, LegacyMutableIndexer } from "Legacy.Tools"

            fun makeIndexer(value: int): LegacyMutableIndexer {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer[1] = value
              indexer
            }

            fun makeIndex(): int = 1

            export fun multiplyAt(value: int, factor: int): int {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer[0] = value
              indexer[0] *= factor
              indexer[0]
            }

            export fun divideAt(value: int, divisor: int): int {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer[0] = value
              indexer[0] /= divisor
              indexer[0]
            }

            export fun moduloAt(value: int, remainder: int): int {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer[0] = value
              indexer[0] %= remainder
              indexer[0]
            }

            export fun checkedMultiplyAt(value: int, factor: int): int {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer[0] = value
              checked(indexer[0] *= factor)
              indexer[0]
            }

            export fun checkedDivideAt(value: int, divisor: int): int {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer[0] = value
              checked(indexer[0] /= divisor)
              indexer[0]
            }

            export fun checkedModuloAt(value: int, remainder: int): int {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer[0] = value
              checked(indexer[0] %= remainder)
              indexer[0]
            }

            export fun uncheckedMultiplyAt(value: int, factor: int): int {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer[0] = value
              unchecked(indexer[0] *= factor)
              indexer[0]
            }

            export fun uncheckedDivideAt(value: int, divisor: int): int {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer[0] = value
              unchecked(indexer[0] /= divisor)
              indexer[0]
            }

            export fun uncheckedModuloAt(value: int, remainder: int): int {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer[0] = value
              unchecked(indexer[0] %= remainder)
              indexer[0]
            }

            export fun nonTrivial(value: int, factor: int): int {
              makeIndexer(value)[makeIndex()] *= factor
            }

            export fun checkedNonTrivial(value: int, factor: int): int {
              checked(makeIndexer(value + 1)[makeIndex()] *= factor)
              value
            }

            export fun uncheckedNonTrivial(value: int, divisor: int): int {
              unchecked(makeIndexer(value + 2)[makeIndex()] /= divisor)
              value
            }

            export fun scaleFloatAt(value: float, factor: int): float {
              let indexer: LegacyFloatIndexer = LegacyFloatIndexer()
              indexer[0] = value
              indexer[0] *= factor
              indexer[0] /= factor
              indexer[0] %= 2
              indexer[0]
            }

            export fun scaleDoubleAt(value: double, factor: float): double {
              let indexer: LegacyDoubleIndexer = LegacyDoubleIndexer()
              indexer[0] = value
              indexer[0] *= factor
              indexer[0] /= 2
              indexer[0] %= factor
              indexer[0]
            }

            export fun scaleDecimalAt(value: decimal, factor: int): decimal {
              let indexer: LegacyDecimalIndexer = LegacyDecimalIndexer()
              indexer[0] = value
              indexer[0] *= factor
              indexer[0] /= 2m
              indexer[0] %= factor
              indexer[0]
            }

            export fun checkedScaleFloatAt(value: float, factor: int): float {
              let indexer: LegacyFloatIndexer = LegacyFloatIndexer()
              indexer[0] = value
              checked(indexer[0] *= factor)
              checked(indexer[0] /= factor)
              checked(indexer[0] %= 2)
              indexer[0]
            }

            export fun uncheckedScaleDecimalAt(value: decimal, factor: int): decimal {
              let indexer: LegacyDecimalIndexer = LegacyDecimalIndexer()
              indexer[0] = value
              unchecked(indexer[0] *= factor)
              unchecked(indexer[0] /= 2m)
              unchecked(indexer[0] %= factor)
              indexer[0]
            }
            """);
        using var output = new StringWriter();
        using var error = new StringWriter();

        var exitCode = TypeSharpCli.Run(["build", manifestPath], output, error);

        AssertTrue(
            exitCode == 0,
            $"Imported C# indexer multiplicative compound assignment API build should succeed.\nSTDOUT:\n{output}\nSTDERR:\n{error}");
        AssertContains("Generated assembly: bin/Debug/net48/ImportedMultiplicativeCompoundAssignmentIndexerApi.dll", output.ToString());
        AssertEqual(string.Empty, error.ToString());

        var generatedSource = File.ReadAllText(Path.Combine(root, "generated", "src", "Main.g.cs")).Replace("\r\n", "\n", StringComparison.Ordinal);
        AssertContains("indexer[0] *= factor;", generatedSource);
        AssertContains("indexer[0] /= divisor;", generatedSource);
        AssertContains("indexer[0] %= remainder;", generatedSource);
        AssertContains("checked\n            {\n                indexer[0] *= factor;\n            }", generatedSource);
        AssertContains("checked\n            {\n                indexer[0] /= divisor;\n            }", generatedSource);
        AssertContains("checked\n            {\n                indexer[0] %= remainder;\n            }", generatedSource);
        AssertContains("unchecked\n            {\n                indexer[0] *= factor;\n            }", generatedSource);
        AssertContains("unchecked\n            {\n                indexer[0] /= divisor;\n            }", generatedSource);
        AssertContains("unchecked\n            {\n                indexer[0] %= remainder;\n            }", generatedSource);
        AssertContains("makeIndexer(value)[makeIndex()] *= factor;", generatedSource);
        AssertContains("checked\n            {\n                makeIndexer(value + 1)[makeIndex()] *= factor;\n            }", generatedSource);
        AssertContains("unchecked\n            {\n                makeIndexer(value + 2)[makeIndex()] /= divisor;\n            }", generatedSource);
        AssertContains("indexer[0] *= factor;", generatedSource);
        AssertContains("indexer[0] /= factor;", generatedSource);
        AssertContains("indexer[0] %= 2;", generatedSource);
        AssertContains("indexer[0] /= 2m;", generatedSource);
        AssertEqual(1, CountOccurrences(generatedSource, "makeIndexer(value)[makeIndex()] *= factor;"));
        AssertEqual(1, CountOccurrences(generatedSource, "makeIndexer(value + 1)[makeIndex()] *= factor;"));
        AssertEqual(1, CountOccurrences(generatedSource, "makeIndexer(value + 2)[makeIndex()] /= divisor;"));

        var generatedAssemblyPath = Path.Combine(root, "generated", "bin", "Debug", "net48", "ImportedMultiplicativeCompoundAssignmentIndexerApi.dll");
        AssertTrue(File.Exists(generatedAssemblyPath), "Build should produce generated net48 assembly with imported indexer multiplicative compound assignment APIs.");

        var consumerRoot = Path.Combine(root, "Consumer");
        Directory.CreateDirectory(consumerRoot);
        WriteFile(consumerRoot, "ImportedMultiplicativeCompoundAssignmentIndexerConsumer.csproj", """
            <Project Sdk="Microsoft.NET.Sdk">
              <PropertyGroup>
                <TargetFramework>net48</TargetFramework>
                <LangVersion>7.3</LangVersion>
                <ImplicitUsings>false</ImplicitUsings>
                <Nullable>disable</Nullable>
                <AssemblyName>ImportedMultiplicativeCompoundAssignmentIndexerConsumer</AssemblyName>
              </PropertyGroup>
              <ItemGroup>
                <Reference Include="ImportedMultiplicativeCompoundAssignmentIndexerApi">
                  <HintPath>../generated/bin/Debug/net48/ImportedMultiplicativeCompoundAssignmentIndexerApi.dll</HintPath>
                </Reference>
                <Reference Include="Legacy.Tools">
                  <HintPath>../lib/Legacy.Tools.dll</HintPath>
                </Reference>
              </ItemGroup>
            </Project>
            """);
        WriteFile(consumerRoot, "NuGet.config", """
            <?xml version="1.0" encoding="utf-8"?>
            <configuration>
              <packageSources>
                <clear />
              </packageSources>
            </configuration>
            """);
        WriteFile(consumerRoot, "Consumer.cs", """
            namespace ImportedMultiplicativeCompoundAssignmentIndexerConsumer
            {
                public static class Consumer
                {
                    public static bool Read()
                    {
                        return Samples.ImportedMultiplicativeCompoundAssignmentIndexers.Module.multiplyAt(5, 4) == 20 &&
                            Samples.ImportedMultiplicativeCompoundAssignmentIndexers.Module.divideAt(21, 3) == 7 &&
                            Samples.ImportedMultiplicativeCompoundAssignmentIndexers.Module.moduloAt(22, 5) == 2 &&
                            Samples.ImportedMultiplicativeCompoundAssignmentIndexers.Module.checkedMultiplyAt(5, 4) == 20 &&
                            Samples.ImportedMultiplicativeCompoundAssignmentIndexers.Module.checkedDivideAt(21, 3) == 7 &&
                            Samples.ImportedMultiplicativeCompoundAssignmentIndexers.Module.checkedModuloAt(22, 5) == 2 &&
                            Samples.ImportedMultiplicativeCompoundAssignmentIndexers.Module.uncheckedMultiplyAt(5, 4) == 20 &&
                            Samples.ImportedMultiplicativeCompoundAssignmentIndexers.Module.uncheckedDivideAt(21, 3) == 7 &&
                            Samples.ImportedMultiplicativeCompoundAssignmentIndexers.Module.uncheckedModuloAt(22, 5) == 2 &&
                            Samples.ImportedMultiplicativeCompoundAssignmentIndexers.Module.nonTrivial(11, 3) == 33 &&
                            Samples.ImportedMultiplicativeCompoundAssignmentIndexers.Module.checkedNonTrivial(11, 3) == 11 &&
                            Samples.ImportedMultiplicativeCompoundAssignmentIndexers.Module.uncheckedNonTrivial(11, 3) == 11 &&
                            Samples.ImportedMultiplicativeCompoundAssignmentIndexers.Module.scaleFloatAt(13f, 3) == 1f &&
                            Samples.ImportedMultiplicativeCompoundAssignmentIndexers.Module.scaleDoubleAt(13.0, 3f) == 1.0 &&
                            Samples.ImportedMultiplicativeCompoundAssignmentIndexers.Module.scaleDecimalAt(13m, 3) == 1m &&
                            Samples.ImportedMultiplicativeCompoundAssignmentIndexers.Module.checkedScaleFloatAt(13f, 3) == 1f &&
                            Samples.ImportedMultiplicativeCompoundAssignmentIndexers.Module.uncheckedScaleDecimalAt(13m, 3) == 1m;
                    }
                }
            }
            """);

        var build = RunProcess("dotnet", "build ImportedMultiplicativeCompoundAssignmentIndexerConsumer.csproj --nologo --verbosity quiet --ignore-failed-sources", consumerRoot);

        AssertTrue(
            build.ExitCode == 0,
            $"C# net48 consumer project should compile against generated imported indexer multiplicative compound assignment APIs.\nSTDOUT:\n{build.StandardOutput}\nSTDERR:\n{build.StandardError}");
    });
