        WriteFile(root, "src/Main.tysh", """
            namespace Samples.InvalidImportedMultiplicativeCompoundAssignmentIndexers

            import { LegacyAmbiguousIndexer, LegacyBoolIndexer, LegacyByteIndexer, LegacyColor, LegacyColorIndexer, LegacyDecimalIndexer, LegacyDualNamed, LegacyFloatIndexer, LegacyMutableIndexer, LegacyStringIndexer } from "Legacy.Tools"

            export fun missingSetter(): int {
              let indexer: LegacyByteIndexer = LegacyByteIndexer()
              indexer[1] *= 2
              0
            }

            export fun boolOperand(): int {
              let indexer: LegacyBoolIndexer = LegacyBoolIndexer()
              indexer[0] *= true
              0
            }

            export fun stringOperand(): int {
              let indexer: LegacyStringIndexer = LegacyStringIndexer()
              indexer[0] /= "x"
              0
            }

            export fun enumOperand(color: LegacyColor): int {
              let indexer: LegacyColorIndexer = LegacyColorIndexer()
              indexer[0] *= color
              0
            }

            export fun nullableOperand(value: int?): int {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer[0] %= value
              0
            }

            export fun narrowing(value: long): int {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer[0] *= value
              0
            }

            export fun mixedDecimalFloating(value: double): int {
              let indexer: LegacyDecimalIndexer = LegacyDecimalIndexer()
              indexer[0] = 1m
              indexer[0] *= value
              0
            }

            export fun narrowingFloat(value: double): int {
              let indexer: LegacyFloatIndexer = LegacyFloatIndexer()
              indexer[0] *= value
              0
            }

            export fun nullableFloat(value: float?): int {
              let indexer: LegacyFloatIndexer = LegacyFloatIndexer()
              indexer[0] /= value
              0
            }

            export fun mismatchedArgument(): int {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer[true] *= 2
              0
            }

            export fun ambiguousArgument(): int {
              let indexer: LegacyAmbiguousIndexer = LegacyAmbiguousIndexer()
              indexer[LegacyDualNamed("value")] *= 2
              0
            }
            """);

        var result = TypeSharpChecker.Check(manifestPath);
        const string unsupportedImportedMessage = "Multiplicative compound assignment is supported only for mutable local bindings or readable and writable metadata-backed imported C# field/property/indexer targets; indexer targets require a matching public getter and setter plus supported index arguments, and event, unresolved, and TypeSharp-owned targets are not supported.";

        AssertTrue(result.HasErrors, "Unsupported imported C# multiplicative compound assignment indexer targets should produce diagnostics.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2216" &&
                diagnostic.Message == unsupportedImportedMessage),
            $"Getter-only imported indexer target should be rejected before emission.\n{string.Join(Environment.NewLine, result.Diagnostics.Select(diagnostic => diagnostic.ToCliText()))}");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'bool' and 'bool'."),
            "Imported bool indexer target should reject multiplicative operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '/=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'string' and 'string'."),
            "Imported string indexer target should reject multiplicative operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2217" &&
                diagnostic.Message.Contains("Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type", StringComparison.Ordinal) &&
                diagnostic.Message.Contains("LegacyColor", StringComparison.Ordinal)),
            "Imported enum indexer target should reject multiplicative operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '%=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'int' and 'int?'."),
            "Imported indexer target should reject nullable multiplicative operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Cannot assign multiplicative compound assignment result of type 'long' to 'int'."),
            "Imported indexer target should reject multiplicative results that cannot be assigned back.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'decimal' and 'double'."),
            "Imported decimal indexer target should reject mixed decimal and floating-point operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Cannot assign multiplicative compound assignment result of type 'double' to 'float'."),
            "Imported float indexer target should reject floating-point results that cannot be assigned back.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '/=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'float' and 'float?'."),
            "Imported float indexer target should reject nullable floating-point operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2411" &&
                diagnostic.Message.Contains("does not contain a public instance indexer compatible with argument type(s) 'bool'", StringComparison.Ordinal)),
            "Mismatched imported indexer argument should reuse existing interop diagnostics.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2402" &&
                diagnostic.Message.Contains("matches 2 indexer candidates", StringComparison.Ordinal)),
            "Ambiguous imported indexer argument should reuse existing interop ambiguity diagnostics.");
    });
}

static void CliBuildCompilesNullConditionalImportedMemberMultiplicativeCompoundAssignment()
{
    WithWorkspace(root =>
    {
        BuildLegacyReferenceDll(root, "Legacy.Tools");
        var manifestPath = WriteManifest(root, """
            [project]
            name = "NullConditionalMultiplicativeCompoundAssignmentApi"
            targetFramework = "net48"
            outputType = "library"
            rootNamespace = "Samples.NullConditionalMultiplicativeCompoundAssignment"
            generatedOutputRoot = "generated"

            [references]
            paths = ["lib/Legacy.Tools.dll"]
            """);
        WriteFile(root, "src/Main.tysh", """
            namespace Samples.NullConditionalMultiplicativeCompoundAssignment

            import { LegacyFields, LegacyQuantity } from "Legacy.Tools"

            fun makeFields(value: int): LegacyFields {
              let fields: LegacyFields = LegacyFields()
              fields.MutableCount = value
              fields.MutableQuantity = LegacyQuantity(value)
              fields
            }

            fun missingFields(): LegacyFields? =
              null

            fun makeFactor(): int {
              LegacyFields.MutableStaticName = "called"
              2
            }

            export fun multiplyCount(value: int, factor: short): int {
              let fields: LegacyFields = makeFields(value)
              fields?.MutableCount *= factor
            }

            export fun divideCount(value: int, divisor: int): int {
              let fields: LegacyFields = makeFields(value)
              fields?.MutableCount /= divisor
            }

            export fun moduloCount(value: int, remainder: int): int {
              let fields: LegacyFields = makeFields(value)
              fields?.MutableCount %= remainder
            }

            export fun multiplyQuantityProperty(value: int, factor: int): LegacyQuantity {
              let fields: LegacyFields = makeFields(value)
              fields?.MutableQuantity *= factor
              fields?.MutableQuantity /= 2
              fields?.MutableQuantity %= 5
              fields.MutableQuantity
            }

            export fun multiplyQuantityField(value: int, factor: int): LegacyQuantity {
              let fields: LegacyFields = LegacyFields()
              fields.MutableQuantityField = LegacyQuantity(value)
              fields?.MutableQuantityField *= factor
              fields?.MutableQuantityField /= 2
              fields?.MutableQuantityField %= 7
              fields.MutableQuantityField
            }

            export fun multiplyLong(value: long): long {
              let fields: LegacyFields = LegacyFields()
              fields.MutableLong = value
              fields?.MutableLong *= 3
            }

            export fun multiplyFloat(value: float, factor: int): float {
              let fields: LegacyFields = LegacyFields()
              fields.MutableFloat = value
              fields?.MutableFloat *= factor
              fields?.MutableFloat /= factor
              fields?.MutableFloat %= 2
              fields.MutableFloat
            }

            export fun multiplyDouble(value: double, factor: float): double {
              let fields: LegacyFields = LegacyFields()
              fields.MutableDouble = value
              fields?.MutableDouble *= factor
              fields?.MutableDouble /= factor
              fields?.MutableDouble %= 2
              fields.MutableDouble
            }

            export fun multiplyDecimal(value: decimal, factor: int): decimal {
              let fields: LegacyFields = LegacyFields()
              fields.MutableDecimal = value
              fields?.MutableDecimal *= factor
              fields?.MutableDecimal /= factor
              fields?.MutableDecimal %= 2m
              fields.MutableDecimal
            }

            export fun skipped(): string {
              LegacyFields.MutableStaticName = "ready"
              let fields: LegacyFields? = missingFields()
              fields?.MutableCount *= makeFactor()
              LegacyFields.MutableStaticName
            }

            export fun skippedQuantity(): string {
              LegacyFields.MutableStaticName = "ready"
              let fields: LegacyFields? = missingFields()
              fields?.MutableQuantity *= makeFactor()
              LegacyFields.MutableStaticName
            }

            export fun nonTrivial(value: int): int {
              makeFields(value)?.MutableCount *= 3
            }

            export fun nonTrivialQuantity(value: int): LegacyQuantity {
              makeFields(value)?.MutableQuantity *= 3
            }

            export fun checkedMember(value: int, factor: int): int {
              let fields: LegacyFields = makeFields(value)
              checked(fields?.MutableCount *= factor)
              checked(fields?.MutableCount /= 2)
              checked(fields?.MutableCount %= 5)
              fields.MutableCount
            }

            export fun uncheckedMember(value: long, divisor: long): long {
              let fields: LegacyFields = LegacyFields()
              fields.MutableLong = value
              unchecked(fields?.MutableLong *= 3)
              unchecked(fields?.MutableLong /= divisor)
              unchecked(fields?.MutableLong %= 7)
              fields.MutableLong
            }

            export fun checkedSkipped(): string {
              LegacyFields.MutableStaticName = "ready"
              let fields: LegacyFields? = missingFields()
              checked(fields?.MutableCount *= makeFactor())
              LegacyFields.MutableStaticName
            }

            export fun checkedNonTrivial(value: int): int {
              checked(makeFields(value)?.MutableCount *= 3)
              0
            }
            """);
        using var output = new StringWriter();
        using var error = new StringWriter();

        var exitCode = TypeSharpCli.Run(["build", manifestPath], output, error);

        AssertTrue(
            exitCode == 0,
            $"Null-conditional imported member multiplicative compound assignment build should succeed.\nSTDOUT:\n{output}\nSTDERR:\n{error}");
        AssertContains("Generated assembly: bin/Debug/net48/NullConditionalMultiplicativeCompoundAssignmentApi.dll", output.ToString());
        AssertEqual(string.Empty, error.ToString());

        var generatedSource = File.ReadAllText(Path.Combine(root, "generated", "src", "Main.g.cs")).Replace("\r\n", "\n", StringComparison.Ordinal);
        AssertContains("new System.Func<LegacyFields, int>(__tsReceiver", generatedSource);
        AssertContains(" == null ? default(int) : (__tsReceiver", generatedSource);
        AssertContains(".MutableCount *= factor)", generatedSource);
        AssertContains(".MutableCount /= divisor)", generatedSource);
        AssertContains(".MutableCount %= remainder)", generatedSource);
        AssertContains("new System.Func<LegacyFields, Legacy.Tools.LegacyQuantity>(__tsReceiver", generatedSource);
        AssertContains(".MutableQuantity *= factor)", generatedSource);
        AssertContains(".MutableQuantity /= 2)", generatedSource);
        AssertContains(".MutableQuantity %= 5)", generatedSource);
        AssertContains(".MutableQuantityField *= factor)", generatedSource);
        AssertContains(".MutableQuantityField /= 2)", generatedSource);
        AssertContains(".MutableQuantityField %= 7)", generatedSource);
        AssertContains(".MutableQuantity *= makeFactor())", generatedSource);
        AssertContains(".MutableQuantity *= 3)", generatedSource);
        AssertContains(".MutableCount *= makeFactor())", generatedSource);
        AssertContains("new System.Func<LegacyFields, long>(__tsReceiver", generatedSource);
        AssertContains(".MutableLong *= 3)", generatedSource);
        AssertContains("new System.Func<LegacyFields, float>(__tsReceiver", generatedSource);
        AssertContains(".MutableFloat *= factor)", generatedSource);
        AssertContains(".MutableFloat /= factor)", generatedSource);
        AssertContains(".MutableFloat %= 2)", generatedSource);
        AssertContains("new System.Func<LegacyFields, double>(__tsReceiver", generatedSource);
        AssertContains(".MutableDouble *= factor)", generatedSource);
        AssertContains(".MutableDouble /= factor)", generatedSource);
        AssertContains(".MutableDouble %= 2)", generatedSource);
        AssertContains("new System.Func<LegacyFields, decimal>(__tsReceiver", generatedSource);
        AssertContains(".MutableDecimal *= factor)", generatedSource);
        AssertContains(".MutableDecimal /= factor)", generatedSource);
        AssertContains(".MutableDecimal %= 2m)", generatedSource);
        AssertContains("checked { return (__tsReceiver", generatedSource);
        AssertContains(".MutableCount *= factor); }", generatedSource);
        AssertContains(".MutableCount /= 2); }", generatedSource);
        AssertContains(".MutableCount %= 5); }", generatedSource);
        AssertContains("unchecked { return (__tsReceiver", generatedSource);
        AssertContains(".MutableLong *= 3); }", generatedSource);
        AssertContains(".MutableLong /= divisor); }", generatedSource);
        AssertContains(".MutableLong %= 7); }", generatedSource);
        AssertContains(".MutableCount *= makeFactor()); }", generatedSource);
        AssertContains(")(makeFields(value))", generatedSource);
        var nullGuardIndex = generatedSource.IndexOf("if (__tsReceiver", StringComparison.Ordinal);
        var checkedBlockIndex = generatedSource.IndexOf("checked { return (__tsReceiver", StringComparison.Ordinal);
        AssertTrue(
            nullGuardIndex >= 0 && checkedBlockIndex > nullGuardIndex,
            "Generated checked null-conditional member multiplicative assignment should place the checked block inside the null guard lambda body.");
        AssertFalse(generatedSource.Contains("?.", StringComparison.Ordinal), "Generated C# 7.3 source should not emit null-conditional multiplicative assignment syntax.");
        AssertFalse(generatedSource.Contains("makeFields(value).MutableCount", StringComparison.Ordinal), "Generated C# should not duplicate a non-trivial null-conditional multiplicative receiver.");

        var generatedAssemblyPath = Path.Combine(root, "generated", "bin", "Debug", "net48", "NullConditionalMultiplicativeCompoundAssignmentApi.dll");
        AssertTrue(File.Exists(generatedAssemblyPath), "Build should produce generated net48 assembly with null-conditional imported member multiplicative compound assignment APIs.");

        var consumerRoot = Path.Combine(root, "Consumer");
        Directory.CreateDirectory(consumerRoot);
        WriteFile(consumerRoot, "NullConditionalMultiplicativeCompoundAssignmentConsumer.csproj", """
            <Project Sdk="Microsoft.NET.Sdk">
              <PropertyGroup>
                <TargetFramework>net48</TargetFramework>
                <LangVersion>7.3</LangVersion>
                <ImplicitUsings>false</ImplicitUsings>
                <Nullable>disable</Nullable>
                <AssemblyName>NullConditionalMultiplicativeCompoundAssignmentConsumer</AssemblyName>
              </PropertyGroup>
              <ItemGroup>
                <Reference Include="NullConditionalMultiplicativeCompoundAssignmentApi">
                  <HintPath>../generated/bin/Debug/net48/NullConditionalMultiplicativeCompoundAssignmentApi.dll</HintPath>
                </Reference>
                <Reference Include="Legacy.Tools">
                  <HintPath>../lib/Legacy.Tools.dll</HintPath>
                </Reference>
              </ItemGroup>
            </Project>
            """);
        WriteFile(consumerRoot, "NuGet.config", """
            <?xml version="1.0" encoding="utf-8"?>
            <configuration>
              <packageSources>
                <clear />
              </packageSources>
            </configuration>
            """);
        WriteFile(consumerRoot, "Consumer.cs", """
            namespace NullConditionalMultiplicativeCompoundAssignmentConsumer
            {
                public static class Consumer
                {
                    public static bool Read()
                    {
                        return Samples.NullConditionalMultiplicativeCompoundAssignment.Module.multiplyCount(5, (short)3) == 15 &&
                            Samples.NullConditionalMultiplicativeCompoundAssignment.Module.divideCount(21, 3) == 7 &&
                            Samples.NullConditionalMultiplicativeCompoundAssignment.Module.moduloCount(22, 5) == 2 &&
                            Samples.NullConditionalMultiplicativeCompoundAssignment.Module.multiplyQuantityProperty(13, 3).Value == 4 &&
                            Samples.NullConditionalMultiplicativeCompoundAssignment.Module.multiplyQuantityField(22, 5).Value == 6 &&
                            Samples.NullConditionalMultiplicativeCompoundAssignment.Module.multiplyLong(4L) == 12L &&
                            Samples.NullConditionalMultiplicativeCompoundAssignment.Module.multiplyFloat(13f, 3) == 1f &&
                            Samples.NullConditionalMultiplicativeCompoundAssignment.Module.multiplyDouble(13.0, 3f) == 1.0 &&
                            Samples.NullConditionalMultiplicativeCompoundAssignment.Module.multiplyDecimal(13m, 3) == 1m &&
                            Samples.NullConditionalMultiplicativeCompoundAssignment.Module.skipped() == "ready" &&
                            Samples.NullConditionalMultiplicativeCompoundAssignment.Module.skippedQuantity() == "ready" &&
                            Samples.NullConditionalMultiplicativeCompoundAssignment.Module.nonTrivial(11) == 33 &&
                            Samples.NullConditionalMultiplicativeCompoundAssignment.Module.nonTrivialQuantity(11).Value == 33 &&
                            Samples.NullConditionalMultiplicativeCompoundAssignment.Module.checkedMember(13, 3) == 4 &&
                            Samples.NullConditionalMultiplicativeCompoundAssignment.Module.uncheckedMember(16L, 4L) == 5L &&
                            Samples.NullConditionalMultiplicativeCompoundAssignment.Module.checkedSkipped() == "ready" &&
                            Samples.NullConditionalMultiplicativeCompoundAssignment.Module.checkedNonTrivial(11) == 0;
                    }
                }
            }
            """);

        var build = RunProcess("dotnet", "build NullConditionalMultiplicativeCompoundAssignmentConsumer.csproj --nologo --verbosity quiet --ignore-failed-sources", consumerRoot);

        AssertTrue(
            build.ExitCode == 0,
            $"C# net48 consumer project should compile against generated null-conditional multiplicative compound assignment APIs.\nSTDOUT:\n{build.StandardOutput}\nSTDERR:\n{build.StandardError}");
    });
}

static void CheckerRejectsUnsupportedNullConditionalImportedMemberMultiplicativeCompoundAssignmentTargets()
{
    WithWorkspace(root =>
    {
        BuildLegacyReferenceDll(root, "Legacy.Tools");
        var manifestPath = WriteManifest(root, """
            [project]
            name = "InvalidNullConditionalMultiplicativeCompoundAssignment"
            targetFramework = "net48"
            outputType = "library"
            rootNamespace = "Samples.InvalidNullConditionalMultiplicativeCompoundAssignment"
            generatedOutputRoot = "generated"

            [references]
            paths = ["lib/Legacy.Tools.dll"]
            """);
        WriteFile(root, "src/Main.tysh", """
            namespace Samples.InvalidNullConditionalMultiplicativeCompoundAssignment

            import { LegacyColor, LegacyEvents, LegacyFields, LegacyOperatorRight } from "Legacy.Tools"

            record Counter {
              Value: int
            }

            export fun boolOperand(): int {
              let fields: LegacyFields = LegacyFields()
              fields?.MutableFlag *= true
              0
            }

            export fun stringOperand(): int {
              let fields: LegacyFields = LegacyFields()
              fields?.MutableCode /= "x"
              0
            }

            export fun enumOperand(color: LegacyColor): int {
              let fields: LegacyFields = LegacyFields()
              fields?.MutableColor *= color
              0
            }

            export fun nullableOperand(value: int?): int {
              let fields: LegacyFields = LegacyFields()
              fields?.MutableCount %= value
              0
            }

            export fun narrowing(value: long): int {
              let fields: LegacyFields = LegacyFields()
              fields?.MutableCount *= value
              0
            }

            export fun mixedDecimalFloating(value: double): int {
              let fields: LegacyFields = LegacyFields()
              fields?.MutableDecimal *= value
              0
            }

            export fun narrowingFloat(value: double): int {
              let fields: LegacyFields = LegacyFields()
              fields?.MutableFloat *= value
              0
            }

            export fun nullableFloat(value: float?): int {
              let fields: LegacyFields = LegacyFields()
              fields?.MutableFloat /= value
              0
            }

            export fun missingOperator(): int {
              let fields: LegacyFields = LegacyFields()
              fields?.MutableScalar *= 2
              0
            }

            export fun nonAssignable(): int {
              let fields: LegacyFields = LegacyFields()
              fields?.MutableBrokenQuantity *= 2
              0
            }

            export fun ambiguousOperator(): int {
              let fields: LegacyFields = LegacyFields()
              let right: LegacyOperatorRight = LegacyOperatorRight(2)
              fields?.MutableOperatorLeft *= right
              0
            }

            export fun nullableQuantityFactor(factor: int?): int {
              let fields: LegacyFields = LegacyFields()
              fields?.MutableQuantity *= factor
              0
            }

            export fun getterOnlyQuantity(): int {
              let fields: LegacyFields = LegacyFields()
              fields?.ReadonlyQuantity *= 2
              0
            }

            export fun readonlyQuantityField(): int {
              let fields: LegacyFields = LegacyFields()
              fields?.ReadonlyQuantityField *= 2
              0
            }

            export fun readonlyField(): int {
              let fields: LegacyFields = LegacyFields()
              fields?.InstanceCode *= "x"
              0
            }

            export fun checkedReadonlyField(): int {
              let fields: LegacyFields = LegacyFields()
              checked(fields?.InstanceCode *= "x")
              0
            }

            export fun eventTarget(): int {
              let events: LegacyEvents = LegacyEvents()
              events?.Transform *= null
              0
            }

            export fun staticTarget(): int {
              LegacyFields?.MutableStaticCount *= 1
              0
            }

            export fun missingMember(): int {
              let fields: LegacyFields = LegacyFields()
              fields?.MissingCount *= 1
              0
            }

            export fun typeSharpOwned(): int {
              let counter: Counter? = null
              counter?.Value *= 1
              0
            }

            export fun localPrimitive(): int {
              let value: int? = null
              value?.Missing *= 1
              0
            }

            """);

        var result = TypeSharpChecker.Check(manifestPath);
        var diagnosticText = string.Join(Environment.NewLine, result.Diagnostics.Select(diagnostic => diagnostic.ToCliText()));

        AssertTrue(result.HasErrors, "Unsupported null-conditional imported C# multiplicative compound assignment targets should produce diagnostics.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'bool' and 'bool'."),
            "Null-conditional imported bool member target should reject multiplicative operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '/=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'string' and 'string'."),
            "Null-conditional imported string member target should reject multiplicative operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2217" &&
                diagnostic.Message.Contains("Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type", StringComparison.Ordinal) &&
                diagnostic.Message.Contains("LegacyColor", StringComparison.Ordinal)),
            "Null-conditional imported enum member target should reject multiplicative operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '%=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'int' and 'int?'."),
            "Null-conditional imported member target should reject nullable multiplicative operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Cannot assign multiplicative compound assignment result of type 'long' to 'int'."),
            "Null-conditional imported member target should reject multiplicative results that cannot be assigned back.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'decimal' and 'double'."),
            "Null-conditional imported decimal member target should reject mixed decimal and floating-point operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Cannot assign multiplicative compound assignment result of type 'double' to 'float'."),
            "Null-conditional imported float member target should reject floating-point results that cannot be assigned back.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '/=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'float' and 'float?'."),
            "Null-conditional imported float member target should reject nullable floating-point operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2217" &&
                diagnostic.Message.Contains("Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type or match one imported C# public static binary operator", StringComparison.Ordinal) &&
                diagnostic.Message.Contains("LegacyScalar", StringComparison.Ordinal)),
            $"Null-conditional imported member target without a matching static binary operator should be rejected.\n{diagnosticText}");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2217" &&
                diagnostic.Message.Contains("Cannot assign user-defined multiplicative compound assignment result of type 'Legacy.Tools.LegacyProduct'", StringComparison.Ordinal) &&
                diagnostic.Message.Contains("LegacyBrokenQuantity", StringComparison.Ordinal)),
            $"Null-conditional imported member target whose operator result cannot assign back should be rejected.\n{diagnosticText}");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2217" &&
                diagnostic.Message.Contains("User-defined multiplicative compound assignment '*=' is ambiguous", StringComparison.Ordinal) &&
                diagnostic.Message.Contains("LegacyOperatorLeft", StringComparison.Ordinal) &&
                diagnostic.Message.Contains("LegacyOperatorRight", StringComparison.Ordinal)),
            $"Ambiguous imported static binary operators should be rejected for null-conditional member targets.\n{diagnosticText}");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2217" &&
                diagnostic.Message.Contains("Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type or match one imported C# public static binary operator", StringComparison.Ordinal) &&
                diagnostic.Message.Contains("LegacyQuantity", StringComparison.Ordinal) &&
                diagnostic.Message.Contains("int?", StringComparison.Ordinal)),
            $"Nullable operands should not bind imported static user-defined operators for null-conditional member targets.\n{diagnosticText}");
        AssertTrue(
            result.Diagnostics.Count(diagnostic =>
                diagnostic.Code == "TS2216" &&
                diagnostic.Message.Contains("readable and writable metadata-backed imported C# instance field/property targets", StringComparison.Ordinal)) >= 9,
            "Getter-only, readonly, checked readonly, event, static, unresolved, TypeSharp-owned, and local null-conditional multiplicative member targets should be rejected before emission.");
    });
}

