            [project]
            name = "NullConditionalIndexerMultiplicativeCompoundAssignmentApi"
            targetFramework = "net48"
            outputType = "library"
            rootNamespace = "Samples.NullConditionalIndexerMultiplicativeCompoundAssignment"
