            [references]
            paths = ["lib/Legacy.Tools.dll"]
            """);
        WriteFile(root, "src/Main.tysh", """
            namespace Samples.NullConditionalIndexerMultiplicativeCompoundAssignment

            import { LegacyDecimalIndexer, LegacyDoubleIndexer, LegacyFields, LegacyFloatIndexer, LegacyMutableIndexer, LegacyQuantity, LegacyQuantityIndexer } from "Legacy.Tools"

            fun makeIndexer(value: int): LegacyMutableIndexer {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer[1] = value
              indexer
            }

            fun makeQuantityIndexer(value: int): LegacyQuantityIndexer {
              let indexer: LegacyQuantityIndexer = LegacyQuantityIndexer()
              indexer[1] = LegacyQuantity(value)
              indexer
            }

            fun missingIndexer(): LegacyMutableIndexer? =
              null

            fun missingQuantityIndexer(): LegacyQuantityIndexer? =
              null

            fun makeIndex(): int {
              LegacyFields.MutableStaticName = "index"
              1
            }

            fun makeFactor(): int {
              LegacyFields.MutableStaticName = "factor"
              2
            }

            export fun multiplyAt(value: int, factor: short): int {
              let indexer: LegacyMutableIndexer = makeIndexer(value)
              indexer?[1] *= factor
            }

            export fun divideAt(value: int, divisor: int): int {
              let indexer: LegacyMutableIndexer = makeIndexer(value)
              indexer?[1] /= divisor
            }

            export fun moduloAt(value: int, remainder: int): int {
              let indexer: LegacyMutableIndexer = makeIndexer(value)
              indexer?[1] %= remainder
            }

            export fun skipped(): string {
              LegacyFields.MutableStaticName = "ready"
              let indexer: LegacyMutableIndexer? = missingIndexer()
              indexer?[makeIndex()] *= makeFactor()
              LegacyFields.MutableStaticName
            }

            export fun nonTrivial(value: int): int {
              makeIndexer(value)?[makeIndex()] *= 3
            }

            export fun scaleFloatAt(value: float, factor: int): float {
              let indexer: LegacyFloatIndexer = LegacyFloatIndexer()
              indexer[0] = value
              indexer?[0] *= factor
              indexer?[0] /= factor
              indexer?[0] %= 2
              indexer[0]
            }

            export fun scaleDoubleAt(value: double, factor: float): double {
              let indexer: LegacyDoubleIndexer = LegacyDoubleIndexer()
              indexer[0] = value
              indexer?[0] *= factor
              indexer?[0] /= 2
              indexer?[0] %= factor
              indexer[0]
            }

            export fun scaleDecimalAt(value: decimal, factor: int): decimal {
              let indexer: LegacyDecimalIndexer = LegacyDecimalIndexer()
              indexer[0] = value
              indexer?[0] *= factor
              indexer?[0] /= 2m
              indexer?[0] %= factor
              indexer[0]
            }

            export fun multiplyQuantityAt(value: int, factor: int): LegacyQuantity {
              let indexer: LegacyQuantityIndexer = makeQuantityIndexer(value)
              indexer?[1] *= factor
              indexer?[1] /= 2
              indexer?[1] %= 5
              indexer[1]
            }

            export fun skippedQuantity(): string {
              LegacyFields.MutableStaticName = "ready"
              let indexer: LegacyQuantityIndexer? = missingQuantityIndexer()
              indexer?[makeIndex()] *= makeFactor()
              LegacyFields.MutableStaticName
            }

            export fun nonTrivialQuantity(value: int): LegacyQuantity {
              makeQuantityIndexer(value)?[makeIndex()] *= 3
            }

            export fun checkedAt(value: int, factor: int): int {
              let indexer: LegacyMutableIndexer = makeIndexer(value)
              checked(indexer?[1] *= factor)
              checked(indexer?[1] /= 2)
              checked(indexer?[1] %= 5)
              indexer[1]
            }

            export fun uncheckedAt(value: int, factor: int): int {
              let indexer: LegacyMutableIndexer = makeIndexer(value)
              unchecked(indexer?[1] *= factor)
              unchecked(indexer?[1] /= 2)
              unchecked(indexer?[1] %= 5)
              indexer[1]
            }

            export fun checkedSkipped(): string {
              LegacyFields.MutableStaticName = "ready"
              let indexer: LegacyMutableIndexer? = missingIndexer()
              checked(indexer?[makeIndex()] *= makeFactor())
              LegacyFields.MutableStaticName
            }

            export fun checkedNonTrivial(value: int): int {
              checked(makeIndexer(value)?[makeIndex()] *= 3)
              0
            }

            export fun uncheckedNonTrivial(value: int): int {
              unchecked(makeIndexer(value)?[makeIndex()] *= 3)
              0
            }
            """);
        using var output = new StringWriter();
        using var error = new StringWriter();

        var exitCode = TypeSharpCli.Run(["build", manifestPath], output, error);

        AssertTrue(
            exitCode == 0,
            $"Null-conditional imported indexer multiplicative compound assignment build should succeed.\nSTDOUT:\n{output}\nSTDERR:\n{error}");
        AssertContains("Generated assembly: bin/Debug/net48/NullConditionalIndexerMultiplicativeCompoundAssignmentApi.dll", output.ToString());
        AssertEqual(string.Empty, error.ToString());

        var generatedSource = File.ReadAllText(Path.Combine(root, "generated", "src", "Main.g.cs")).Replace("\r\n", "\n", StringComparison.Ordinal);
        AssertContains("new System.Func<LegacyMutableIndexer, int>(__tsReceiver", generatedSource);
        AssertContains(" == null ? default(int) : new System.Func<int, int>((__tsIndex", generatedSource);
        AssertContains("] *= factor)", generatedSource);
        AssertContains("] /= divisor)", generatedSource);
        AssertContains("] %= remainder)", generatedSource);
        AssertContains("] *= makeFactor())", generatedSource);
        AssertContains(")(makeIndex())", generatedSource);
        AssertContains(")(makeIndexer(value))", generatedSource);
        AssertContains("new System.Func<LegacyFloatIndexer, float>(__tsReceiver", generatedSource);
        AssertContains(" == null ? default(float) : new System.Func<int, float>((__tsIndex", generatedSource);
        AssertContains("new System.Func<LegacyDoubleIndexer, double>(__tsReceiver", generatedSource);
        AssertContains(" == null ? default(double) : new System.Func<int, double>((__tsIndex", generatedSource);
        AssertContains("new System.Func<LegacyDecimalIndexer, decimal>(__tsReceiver", generatedSource);
        AssertContains(" == null ? default(decimal) : new System.Func<int, decimal>((__tsIndex", generatedSource);
        AssertContains("] /= 2m)", generatedSource);
        AssertContains("new System.Func<LegacyQuantityIndexer, Legacy.Tools.LegacyQuantity>(__tsReceiver", generatedSource);
        AssertContains(" == null ? default(Legacy.Tools.LegacyQuantity) : new System.Func<int, Legacy.Tools.LegacyQuantity>((__tsIndex", generatedSource);
        AssertContains("] /= 2)", generatedSource);
        AssertContains("] %= 5)", generatedSource);
        AssertContains("if (__tsReceiver", generatedSource);
        AssertContains("=> { checked { return (__tsReceiver", generatedSource);
        AssertContains("] *= factor); }", generatedSource);
        AssertContains("] /= 2); }", generatedSource);
        AssertContains("] %= 5); }", generatedSource);
        AssertContains("=> { unchecked { return (__tsReceiver", generatedSource);
        AssertContains("] *= makeFactor()); }", generatedSource);
        AssertContains(")(makeIndex())", generatedSource);
        var nullGuardIndex = generatedSource.IndexOf("if (__tsReceiver", StringComparison.Ordinal);
        var checkedBlockIndex = generatedSource.IndexOf("=> { checked { return (__tsReceiver", StringComparison.Ordinal);
        AssertTrue(
            nullGuardIndex >= 0 && checkedBlockIndex > nullGuardIndex,
            "Generated checked null-conditional indexer multiplicative assignment should place the checked block inside the null/index guard lowering.");
        AssertFalse(generatedSource.Contains("?[", StringComparison.Ordinal), "Generated C# 7.3 source should not emit null-conditional indexer multiplicative assignment syntax.");
        AssertFalse(generatedSource.Contains("makeIndexer(value)[makeIndex()]", StringComparison.Ordinal), "Generated C# should not duplicate a non-trivial null-conditional multiplicative indexer receiver or argument.");
        AssertFalse(generatedSource.Contains("makeQuantityIndexer(value)[makeIndex()]", StringComparison.Ordinal), "Generated C# should not duplicate a non-trivial null-conditional user-defined multiplicative indexer receiver or argument.");

        var generatedAssemblyPath = Path.Combine(root, "generated", "bin", "Debug", "net48", "NullConditionalIndexerMultiplicativeCompoundAssignmentApi.dll");
        AssertTrue(File.Exists(generatedAssemblyPath), "Build should produce generated net48 assembly with null-conditional imported indexer multiplicative compound assignment APIs.");

        var consumerRoot = Path.Combine(root, "Consumer");
        Directory.CreateDirectory(consumerRoot);
        WriteFile(consumerRoot, "NullConditionalIndexerMultiplicativeCompoundAssignmentConsumer.csproj", """
            <Project Sdk="Microsoft.NET.Sdk">
              <PropertyGroup>
                <TargetFramework>net48</TargetFramework>
                <LangVersion>7.3</LangVersion>
                <ImplicitUsings>false</ImplicitUsings>
                <Nullable>disable</Nullable>
                <AssemblyName>NullConditionalIndexerMultiplicativeCompoundAssignmentConsumer</AssemblyName>
              </PropertyGroup>
              <ItemGroup>
                <Reference Include="NullConditionalIndexerMultiplicativeCompoundAssignmentApi">
                  <HintPath>../generated/bin/Debug/net48/NullConditionalIndexerMultiplicativeCompoundAssignmentApi.dll</HintPath>
                </Reference>
                <Reference Include="Legacy.Tools">
                  <HintPath>../lib/Legacy.Tools.dll</HintPath>
                </Reference>
              </ItemGroup>
            </Project>
            """);
        WriteFile(consumerRoot, "NuGet.config", """
            <?xml version="1.0" encoding="utf-8"?>
            <configuration>
              <packageSources>
                <clear />
              </packageSources>
            </configuration>
            """);
        WriteFile(consumerRoot, "Consumer.cs", """
            namespace NullConditionalIndexerMultiplicativeCompoundAssignmentConsumer
            {
                public static class Consumer
                {
                    public static bool Read()
                    {
                        return Samples.NullConditionalIndexerMultiplicativeCompoundAssignment.Module.multiplyAt(5, (short)3) == 15 &&
                            Samples.NullConditionalIndexerMultiplicativeCompoundAssignment.Module.divideAt(21, 3) == 7 &&
                            Samples.NullConditionalIndexerMultiplicativeCompoundAssignment.Module.moduloAt(22, 5) == 2 &&
                            Samples.NullConditionalIndexerMultiplicativeCompoundAssignment.Module.skipped() == "ready" &&
                            Samples.NullConditionalIndexerMultiplicativeCompoundAssignment.Module.nonTrivial(11) == 33 &&
                            Samples.NullConditionalIndexerMultiplicativeCompoundAssignment.Module.scaleFloatAt(13f, 3) == 1f &&
                            Samples.NullConditionalIndexerMultiplicativeCompoundAssignment.Module.scaleDoubleAt(13.0, 3f) == 1.0 &&
                            Samples.NullConditionalIndexerMultiplicativeCompoundAssignment.Module.scaleDecimalAt(13m, 3) == 1.5m &&
                            Samples.NullConditionalIndexerMultiplicativeCompoundAssignment.Module.multiplyQuantityAt(13, 3).Value == 4 &&
                            Samples.NullConditionalIndexerMultiplicativeCompoundAssignment.Module.skippedQuantity() == "ready" &&
                            Samples.NullConditionalIndexerMultiplicativeCompoundAssignment.Module.nonTrivialQuantity(11).Value == 33 &&
                            Samples.NullConditionalIndexerMultiplicativeCompoundAssignment.Module.checkedAt(13, 3) == 4 &&
                            Samples.NullConditionalIndexerMultiplicativeCompoundAssignment.Module.uncheckedAt(16, 4) == 2 &&
                            Samples.NullConditionalIndexerMultiplicativeCompoundAssignment.Module.checkedSkipped() == "ready" &&
                            Samples.NullConditionalIndexerMultiplicativeCompoundAssignment.Module.checkedNonTrivial(11) == 0 &&
                            Samples.NullConditionalIndexerMultiplicativeCompoundAssignment.Module.uncheckedNonTrivial(11) == 0;
                    }
                }
            }
            """);

        var build = RunProcess("dotnet", "build NullConditionalIndexerMultiplicativeCompoundAssignmentConsumer.csproj --nologo --verbosity quiet --ignore-failed-sources", consumerRoot);

        AssertTrue(
            build.ExitCode == 0,
            $"C# net48 consumer project should compile against generated null-conditional indexer multiplicative compound assignment APIs.\nSTDOUT:\n{build.StandardOutput}\nSTDERR:\n{build.StandardError}");
    });
}

static void CheckerRejectsUnsupportedNullConditionalImportedIndexerMultiplicativeCompoundAssignmentTargets()
{
    WithWorkspace(root =>
    {
        BuildLegacyReferenceDll(root, "Legacy.Tools");
        var manifestPath = WriteManifest(root, """
            [project]
            name = "InvalidNullConditionalIndexerMultiplicativeCompoundAssignment"
            targetFramework = "net48"
            outputType = "library"
            rootNamespace = "Samples.InvalidNullConditionalIndexerMultiplicativeCompoundAssignment"
            generatedOutputRoot = "generated"

            [references]
            paths = ["lib/Legacy.Tools.dll"]
            """);
        WriteFile(root, "src/Main.tysh", """
            namespace Samples.InvalidNullConditionalIndexerMultiplicativeCompoundAssignment

            import { LegacyAmbiguousIndexer, LegacyBoolIndexer, LegacyBrokenQuantityIndexer, LegacyByteIndexer, LegacyColor, LegacyColorIndexer, LegacyDecimalIndexer, LegacyDualNamed, LegacyFields, LegacyFloatIndexer, LegacyMutableIndexer, LegacyOperatorLeftIndexer, LegacyOperatorRight, LegacyQuantityIndexer, LegacyScalarIndexer, LegacyStringIndexer } from "Legacy.Tools"

            record Counter {
              Value: int
            }

            export fun boolOperand(): int {
              let indexer: LegacyBoolIndexer = LegacyBoolIndexer()
              indexer?[0] *= true
              0
            }

            export fun stringOperand(): int {
              let indexer: LegacyStringIndexer = LegacyStringIndexer()
              indexer?[0] /= "x"
              0
            }

            export fun enumOperand(color: LegacyColor): int {
              let indexer: LegacyColorIndexer = LegacyColorIndexer()
              indexer?[0] *= color
              0
            }

            export fun nullableOperand(value: int?): int {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer?[0] %= value
              0
            }

            export fun narrowing(value: long): int {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer?[0] *= value
              0
            }

            export fun mixedDecimalFloating(value: double): int {
              let indexer: LegacyDecimalIndexer = LegacyDecimalIndexer()
              indexer?[0] *= value
              0
            }

            export fun narrowingFloat(value: double): int {
              let indexer: LegacyFloatIndexer = LegacyFloatIndexer()
              indexer?[0] *= value
              0
            }

            export fun nullableFloat(value: float?): int {
              let indexer: LegacyFloatIndexer = LegacyFloatIndexer()
              indexer?[0] /= value
              0
            }

            export fun missingSetter(): int {
              let indexer: LegacyByteIndexer = LegacyByteIndexer()
              indexer?[1] *= 2
              0
            }

            export fun mismatchedArgument(): int {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer?[true] *= 2
              0
            }

            export fun ambiguousArgument(): int {
              let indexer: LegacyAmbiguousIndexer = LegacyAmbiguousIndexer()
              indexer?[LegacyDualNamed("value")] *= 2
              0
            }

            export fun missingIndexer(): int {
              let fields: LegacyFields = LegacyFields()
              fields?[1] *= 2
              0
            }

            export fun typeSharpOwned(): int {
              let counter: Counter? = null
              counter?[1] *= 2
              0
            }

            export fun localPrimitive(): int {
              let value: int? = null
              value?[1] /= 2
              0
            }

            export fun staticTarget(): int {
              LegacyMutableIndexer?[1] %= 2
              0
            }

            export fun checkedBoolOperand(): int {
              let indexer: LegacyBoolIndexer = LegacyBoolIndexer()
              checked(indexer?[0] *= true)
              0
            }

            export fun uncheckedMissingSetter(): int {
              let indexer: LegacyByteIndexer = LegacyByteIndexer()
              unchecked(indexer?[1] *= 2)
              0
            }

            export fun checkedMismatchedArgument(): int {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              checked(indexer?[true] *= 2)
              0
            }

            export fun uncheckedAmbiguousArgument(): int {
              let indexer: LegacyAmbiguousIndexer = LegacyAmbiguousIndexer()
              unchecked(indexer?[LegacyDualNamed("value")] *= 2)
              0
            }

            export fun checkedTypeSharpOwned(): int {
              let counter: Counter? = null
              checked(counter?[1] *= 2)
              0
            }

            export fun missingOperatorNullConditional(): int {
              let indexer: LegacyScalarIndexer = LegacyScalarIndexer()
              indexer?[0] *= 2
              0
            }

            export fun nonAssignableNullConditional(): int {
              let indexer: LegacyBrokenQuantityIndexer = LegacyBrokenQuantityIndexer()
              indexer?[0] *= 2
              0
            }

            export fun ambiguousOperatorNullConditional(): int {
              let indexer: LegacyOperatorLeftIndexer = LegacyOperatorLeftIndexer()
              let right: LegacyOperatorRight = LegacyOperatorRight(2)
              indexer?[0] *= right
              0
            }

            export fun nullableQuantityFactorNullConditional(factor: int?): int {
              let indexer: LegacyQuantityIndexer = LegacyQuantityIndexer()
              indexer?[0] *= factor
              0
            }
            """);

        var result = TypeSharpChecker.Check(manifestPath);

        AssertTrue(result.HasErrors, "Unsupported null-conditional imported C# indexer multiplicative compound assignment targets should produce diagnostics.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'bool' and 'bool'."),
            "Null-conditional imported bool indexer target should reject multiplicative operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '/=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'string' and 'string'."),
            "Null-conditional imported string indexer target should reject multiplicative operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2217" &&
                diagnostic.Message.Contains("Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type", StringComparison.Ordinal) &&
                diagnostic.Message.Contains("LegacyColor", StringComparison.Ordinal)),
            "Null-conditional imported enum indexer target should reject multiplicative operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '%=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'int' and 'int?'."),
            "Null-conditional imported indexer target should reject nullable multiplicative operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Cannot assign multiplicative compound assignment result of type 'long' to 'int'."),
            "Null-conditional imported indexer target should reject multiplicative results that cannot be assigned back.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'decimal' and 'double'."),
            "Null-conditional imported decimal indexer target should reject mixed decimal and floating-point operands.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Cannot assign multiplicative compound assignment result of type 'double' to 'float'."),
            "Null-conditional imported float indexer target should reject floating-point results that cannot be assigned back.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '/=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'float' and 'float?'."),
            "Null-conditional imported float indexer target should reject nullable floating-point operands.");
        AssertTrue(
            result.Diagnostics.Count(diagnostic =>
                diagnostic.Code == "TS2216" &&
                diagnostic.Message.Contains("readable and writable metadata-backed imported C# instance indexer targets", StringComparison.Ordinal)) >= 5,
            "Getter-only, checked getter-only, unresolved, local, static-like, and TypeSharp-owned null-conditional indexer multiplicative targets should be rejected before emission.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2411" &&
                diagnostic.Message.Contains("does not contain a public instance indexer compatible with argument type(s) 'bool'", StringComparison.Ordinal)),
            "Mismatched null-conditional imported indexer multiplicative arguments should reuse existing interop diagnostics.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2402" &&
                diagnostic.Message.Contains("matches 2 indexer candidates", StringComparison.Ordinal)),
            "Ambiguous null-conditional imported indexer multiplicative arguments should reuse existing interop ambiguity diagnostics.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2217" &&
                diagnostic.Message.Contains("Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type or match one imported C# public static binary operator", StringComparison.Ordinal) &&
                diagnostic.Message.Contains("LegacyScalar", StringComparison.Ordinal)),
            $"Null-conditional imported indexer target without a matching static binary operator should be rejected.\n{string.Join(Environment.NewLine, result.Diagnostics.Select(d => d.ToCliText()))}");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2217" &&
                diagnostic.Message.Contains("Cannot assign user-defined multiplicative compound assignment result of type 'Legacy.Tools.LegacyProduct'", StringComparison.Ordinal) &&
                diagnostic.Message.Contains("LegacyBrokenQuantity", StringComparison.Ordinal)),
            $"Null-conditional imported indexer target whose user-defined operator result cannot assign back should be rejected.\n{string.Join(Environment.NewLine, result.Diagnostics.Select(d => d.ToCliText()))}");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2217" &&
                diagnostic.Message.Contains("User-defined multiplicative compound assignment '*=' is ambiguous", StringComparison.Ordinal) &&
                diagnostic.Message.Contains("LegacyOperatorLeft", StringComparison.Ordinal) &&
                diagnostic.Message.Contains("LegacyOperatorRight", StringComparison.Ordinal)),
            $"Ambiguous imported static binary operators should be rejected for null-conditional indexer targets.\n{string.Join(Environment.NewLine, result.Diagnostics.Select(d => d.ToCliText()))}");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2217" &&
                diagnostic.Message.Contains("Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type or match one imported C# public static binary operator", StringComparison.Ordinal) &&
                diagnostic.Message.Contains("LegacyQuantity", StringComparison.Ordinal) &&
                diagnostic.Message.Contains("int?", StringComparison.Ordinal)),
            $"Nullable factor operands should not bind imported static user-defined operators for null-conditional indexer targets.\n{string.Join(Environment.NewLine, result.Diagnostics.Select(d => d.ToCliText()))}");
    });
}

static void CheckerRejectsUnsupportedMultiplicativeCompoundAssignmentTargets()
{
    WithWorkspace(root =>
    {
        BuildLegacyReferenceDll(root, "Legacy.Tools");
        var manifestPath = WriteManifest(root, """
            [project]
            name = "InvalidMultiplicativeCompoundAssignment"
            targetFramework = "net48"
            outputType = "library"
            rootNamespace = "Samples.InvalidMultiplicativeCompoundAssignment"
            generatedOutputRoot = "generated"

            [references]
            paths = ["lib/Legacy.Tools.dll"]
            """);
        WriteFile(root, "src/Main.tysh", """
            namespace Samples.InvalidMultiplicativeCompoundAssignment

            import { LegacyByteIndexer, LegacyFields, LegacyMutableIndexer } from "Legacy.Tools"

            enum RateKind {
              Basic
              Advanced
            }

            export fun immutableLocal(): int {
              let value = 1
              value *= 2
              value
            }

            export fun invalidTarget(): int {
              1 %= 2
              0
            }

            export fun boolTarget(): bool {
              let mut flag = true
              flag *= false
              flag
            }

            export fun stringTarget(): string {
              let mut text = "ok"
              text /= "x"
              text
            }

            export fun nullableOperand(): int {
              let mut value: int = 1
              let maybe: int? = null
              value %= maybe
              value
            }

            export fun nonAssignableResult(value: int, extra: long): int {
              let mut result = value
              result *= extra
              result
            }

            export fun enumTarget(kind: RateKind): RateKind {
              let mut current = kind
              current *= kind
              current
            }

            export fun mixedDecimalFloating(value: decimal, factor: double): decimal {
              let mut result = value
              result *= factor
              result
            }

            export fun narrowingFloat(value: float, factor: double): float {
              let mut result = value
              result *= factor
              result
            }

            export fun nullableFloat(value: float, maybe: float?): float {
              let mut result = value
              result /= maybe
              result
            }

            export fun checkedImportedMember(value: int, factor: int): int {
              let fields: LegacyFields = LegacyFields()
              fields.MutableCount = value
              checked(fields.MutableCount *= factor)
              fields.MutableCount
            }

            export fun uncheckedImportedIndexer(value: int, factor: int): int {
              let indexer: LegacyMutableIndexer = LegacyMutableIndexer()
              indexer[0] = value
              unchecked(indexer[0] *= factor)
              indexer[0]
            }

            export fun uncheckedNullConditionalIndexerMissingSetter(indexer: LegacyByteIndexer): int {
              unchecked(indexer?[0] *= 2)
              0
            }

            export fun checkedMixedDecimalFloating(value: decimal, factor: double): decimal {
              let mut result = value
              checked(result *= factor)
              result
            }

            export fun uncheckedNullableFloat(value: float, maybe: float?): float {
              let mut result = value
              unchecked(result /= maybe)
              result
            }

            export fun importedIndexerMissingSetter(): int {
              let indexer: LegacyByteIndexer = LegacyByteIndexer()
              indexer[0] /= 2
              0
            }

            export fun checkedImportedIndexerMissingSetter(): int {
              let indexer: LegacyByteIndexer = LegacyByteIndexer()
              checked(indexer[0] /= 2)
              0
            }
            """);

        var result = TypeSharpChecker.Check(manifestPath);
        const string unsupportedImportedMessage = "Multiplicative compound assignment is supported only for mutable local bindings or readable and writable metadata-backed imported C# field/property/indexer targets; indexer targets require a matching public getter and setter plus supported index arguments, and event, unresolved, and TypeSharp-owned targets are not supported.";
        const string unsupportedNullConditionalIndexerMessage = "Null-conditional multiplicative compound assignment '?[]' is supported only for readable and writable metadata-backed imported C# instance indexer targets with a matching public getter and setter.";
        const string mixedDecimalFloatingMessage = "Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'decimal' and 'double'.";
        const string nullableFloatMessage = "Multiplicative compound assignment '/=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'float' and 'float?'.";
        var diagnosticText = string.Join(Environment.NewLine, result.Diagnostics.Select(diagnostic => diagnostic.ToCliText()));

        AssertTrue(result.HasErrors, "Unsupported multiplicative compound assignment targets should produce diagnostics.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2216" &&
                diagnostic.Message == "Cannot assign to immutable binding 'value'. Use 'let mut' when mutation is intended."),
            $"Immutable local multiplicative assignment should preserve the local mutability diagnostic.\n{diagnosticText}");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2216" &&
                diagnostic.Message == "Assignment target must be a mutable local binding or a supported imported C# member, indexer, or event target."),
            "Non-binding multiplicative assignment targets should be rejected before emission.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'bool' and 'bool'."),
            "Bool multiplicative operands should be rejected.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '/=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'string' and 'string'."),
            "String multiplicative operands should be rejected.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '%=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'int' and 'int?'."),
            "Nullable multiplicative operands should be rejected.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Cannot assign multiplicative compound assignment result of type 'long' to 'int'."),
            "Promoted multiplicative results that cannot be assigned back should be rejected.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'RateKind' and 'RateKind'."),
            "Enum multiplicative operands should be rejected.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '*=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'decimal' and 'double'."),
            "Mixed decimal and floating-point multiplicative operands should be rejected.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Cannot assign multiplicative compound assignment result of type 'double' to 'float'."),
            "Floating-point multiplicative results that cannot be assigned back should be rejected.");
        AssertTrue(
            result.Diagnostics.Any(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == "Multiplicative compound assignment '/=' operands must be non-null primitive numeric values of a supported integral, floating-point, or decimal type, but found 'float' and 'float?'."),
            "Nullable floating-point multiplicative operands should be rejected.");
        AssertTrue(
            result.Diagnostics.Count(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == mixedDecimalFloatingMessage) >= 2,
            "Checked local mixed decimal/floating operands should preserve existing multiplicative diagnostics.");
        AssertTrue(
            result.Diagnostics.Count(diagnostic =>
                diagnostic.Code == "TS2222" &&
                diagnostic.Message == nullableFloatMessage) >= 2,
            "Unchecked local nullable floating-point operands should preserve existing multiplicative diagnostics.");
        AssertTrue(
            result.Diagnostics.Count(diagnostic =>
                diagnostic.Code == "TS2216" &&
                diagnostic.Message == unsupportedImportedMessage) >= 2,
            "Imported C# indexer multiplicative targets without a public setter should remain unsupported inside and outside checked wrappers.");
        AssertTrue(
            result.Diagnostics.Count(diagnostic =>
                diagnostic.Code == "TS2216" &&
                diagnostic.Message == unsupportedNullConditionalIndexerMessage) >= 1,
            "Null-conditional imported C# indexer multiplicative targets without a public setter should remain unsupported inside unchecked wrappers.");
    });
}

static void CliBuildCompilesBooleanBitwiseExpressionApi()
{
    WithWorkspace(root =>
    {
        var manifestPath = WriteManifest(root, """
            [project]
            name = "BooleanBitwiseApi"
            targetFramework = "net48"
            outputType = "library"
            rootNamespace = "Samples.BooleanBitwise"
            generatedOutputRoot = "generated"
            """);
        WriteFile(root, "src/Main.tysh", """
            namespace Samples.BooleanBitwise

            export fun both(left: bool, right: bool): bool =
              left & right

            export fun either(left: bool, right: bool): bool =
              left | right

            export fun toggled(left: bool, right: bool): bool =
              left ^ right

            export fun combined(left: bool, right: bool): bool =
              (left & right) | (left ^ right)
            """);
        using var output = new StringWriter();
        using var error = new StringWriter();

        var exitCode = TypeSharpCli.Run(["build", manifestPath], output, error);

        AssertEqual(0, exitCode);
        AssertContains("Generated assembly: bin/Debug/net48/BooleanBitwiseApi.dll", output.ToString());
        AssertEqual(string.Empty, error.ToString());

        var generatedSource = File.ReadAllText(Path.Combine(root, "generated", "src", "Main.g.cs")).Replace("\r\n", "\n", StringComparison.Ordinal);
        AssertContains("return left & right;", generatedSource);
        AssertContains("return left | right;", generatedSource);
        AssertContains("return left ^ right;", generatedSource);
        AssertContains("return (left & right) | (left ^ right);", generatedSource);

        var generatedAssemblyPath = Path.Combine(root, "generated", "bin", "Debug", "net48", "BooleanBitwiseApi.dll");
        AssertTrue(File.Exists(generatedAssemblyPath), "Build should produce generated net48 assembly with boolean bitwise APIs.");

        var consumerRoot = Path.Combine(root, "Consumer");
