        WriteFile(consumerRoot, "BooleanBitwiseConsumer.csproj", """
            <Project Sdk="Microsoft.NET.Sdk">
              <PropertyGroup>
                <TargetFramework>net48</TargetFramework>
                <LangVersion>7.3</LangVersion>
                <ImplicitUsings>false</ImplicitUsings>
                <Nullable>disable</Nullable>
                <AssemblyName>BooleanBitwiseConsumer</AssemblyName>
              </PropertyGroup>
              <ItemGroup>
                <Reference Include="BooleanBitwiseApi">
                  <HintPath>../generated/bin/Debug/net48/BooleanBitwiseApi.dll</HintPath>
                </Reference>
              </ItemGroup>
            </Project>
            """);
        WriteFile(consumerRoot, "NuGet.config", """
            <?xml version="1.0" encoding="utf-8"?>
            <configuration>
              <packageSources>
                <clear />
              </packageSources>
            </configuration>
            """);
        WriteFile(consumerRoot, "Consumer.cs", """
            namespace BooleanBitwiseConsumer
            {
                public static class Consumer
                {
                    public static bool Read()
                    {
                        return Samples.BooleanBitwise.Module.both(true, false) == false &&
                            Samples.BooleanBitwise.Module.either(true, false) == true &&
                            Samples.BooleanBitwise.Module.toggled(true, false) == true &&
