static void GeneratedNet48AssemblyPublicAbiSnapshotIsStable()
{
    WithWorkspace(root =>
    {
        var manifestPath = WriteManifest(root, """
            [project]
            name = "PublicAbiSnapshot"
            targetFramework = "net48"
            outputType = "library"
            rootNamespace = "Samples.PublicAbi"
            generatedOutputRoot = "generated"
            """);
        WriteFile(root, "src/Main.tysh", """
            namespace Samples.PublicAbi

            public record Customer(Name: string, Age: int)

            export fun describe(customer: Customer): string = customer.Name
            """);
        using var output = new StringWriter();
        using var error = new StringWriter();

        var exitCode = TypeSharpCli.Run(["build", manifestPath], output, error);

        AssertEqual(0, exitCode);
        AssertEqual(string.Empty, error.ToString());
        AssertContains("Generated assembly: bin/Debug/net48/PublicAbiSnapshot.dll", output.ToString());

        var generatedAssemblyPath = Path.Combine(root, "generated", "bin", "Debug", "net48", "PublicAbiSnapshot.dll");
        AssertTrue(File.Exists(generatedAssemblyPath), "Build should produce generated public ABI snapshot assembly.");

        var metadata = TypeSharpMetadataReader.Read(
        [
            new ResolvedReference(
                ResolvedReferenceKind.LocalAssembly,
                "PublicAbiSnapshot",
                generatedAssemblyPath,
                generatedAssemblyPath,
                "generated/bin/Debug/net48/PublicAbiSnapshot.dll")
        ]);

        AssertFalse(metadata.HasErrors, "Generated public ABI snapshot assembly metadata should be readable.");
        var snapshot = TypeSharpPublicAbiChecker.CreateSnapshot(metadata.Assemblies.Single());
        AssertSequence(
        [
            "assembly PublicAbiSnapshot",
            "type Samples.PublicAbi.Customer",
            "  constructor Customer(string Name, int Age)",
            "  property get int Age",
            "  property get string Name",
            "  method bool Equals(object obj)",
            "  method int GetHashCode()",
            "type Samples.PublicAbi.Module",
            "  method static string describe(Samples.PublicAbi.Customer customer)"
        ], snapshot.Lines);
    });
}

static void CSharpNet48ProjectConsumesGeneratedTypeSharpAssembly()
{
    WithWorkspace(root =>
    {
        var manifestPath = WriteManifest(root, """
            [project]
            name = "InteropSource"
            targetFramework = "net48"
            outputType = "library"
            rootNamespace = "Samples.GeneratedInterop"
            generatedOutputRoot = "generated"
            """);
        WriteFile(root, "src/Main.tysh", """
            namespace Samples.GeneratedInterop

            import { ObsoleteAttribute } from "System"

            [ObsoleteAttribute("Use NewTransform.")]
            public delegate Transform(value: string): string

            public delegate Joiner(separator: string, params values: string[]): string

            public delegate ChangedHandler(value: string): unit

            public class Notifier(seed: string) {
              public let Name: string = "instance"

              public let DisplayName: string = "display" { get }

              public let mut DisplayCode: string = "code" { get set }

              public let mut Count: int = 1

              public static let Kind: string = "notifier"

              public static let Build: string = "debug" { get }

              public static let mut Channel: string = "dev" { get set }

              public static let mut MutableKind: string = "mutable"

              public static fun StaticEcho(value: string): string = value

              public static event GlobalChanged: ChangedHandler

              public event Changed: ChangedHandler

              public fun Echo(value: string): string = value
            }

            public interface IListener {
              public event Changed: ChangedHandler

              fun Echo(value: string): string
            }

            export fun greeting(): string = "Hello from TypeSharp"
            """);
        using var output = new StringWriter();
        using var error = new StringWriter();

        var exitCode = TypeSharpCli.Run(["build", manifestPath], output, error);

        AssertEqual(0, exitCode);
        AssertEqual(string.Empty, error.ToString());
        AssertContains("Generated assembly: bin/Debug/net48/InteropSource.dll", output.ToString());

        var generatedAssemblyPath = Path.Combine(root, "generated", "bin", "Debug", "net48", "InteropSource.dll");
        AssertTrue(File.Exists(generatedAssemblyPath), "TypeSharp build should produce a generated assembly for the C# consumer.");
        var generatedSource = File.ReadAllText(Path.Combine(root, "generated", "src", "Main.g.cs")).Replace("\r\n", "\n", StringComparison.Ordinal);
        AssertContains("[ObsoleteAttribute(\"Use NewTransform.\")]", generatedSource);
        AssertContains("public delegate string Transform(string value);", generatedSource);
        AssertContains("public delegate string Joiner(string separator, params string[] values);", generatedSource);
        AssertContains("public delegate void ChangedHandler(string value);", generatedSource);
        AssertContains("public Notifier(string seed)", generatedSource);
        AssertContains("public readonly string Name = \"instance\";", generatedSource);
        AssertContains("public string DisplayName { get; } = \"display\";", generatedSource);
        AssertContains("public string DisplayCode { get; set; } = \"code\";", generatedSource);
        AssertContains("public int Count = 1;", generatedSource);
        AssertContains("public static readonly string Kind = \"notifier\";", generatedSource);
        AssertContains("public static string Build { get; } = \"debug\";", generatedSource);
        AssertContains("public static string Channel { get; set; } = \"dev\";", generatedSource);
        AssertContains("public static string MutableKind = \"mutable\";", generatedSource);
        AssertContains("public static string StaticEcho(string value)", generatedSource);
        AssertContains("public static event ChangedHandler GlobalChanged;", generatedSource);
        AssertContains("public event ChangedHandler Changed;", generatedSource);
        AssertContains("public interface IListener", generatedSource);
        AssertContains("event ChangedHandler Changed;", generatedSource);

        var metadata = TypeSharpMetadataReader.Read(
        [
            new ResolvedReference(
                ResolvedReferenceKind.LocalAssembly,
                "InteropSource",
                generatedAssemblyPath,
                generatedAssemblyPath,
                "generated/bin/Debug/net48/InteropSource.dll")
        ]);

        AssertFalse(metadata.HasErrors, "Generated interop assembly metadata should be readable.");
        var abiSnapshotText = string.Join("\n", TypeSharpPublicAbiChecker.CreateSnapshot(metadata.Assemblies.Single()).Lines);
        AssertContains("type Samples.GeneratedInterop.Joiner", abiSnapshotText);
        AssertContains("  method string Invoke(string separator, params string[] values)", abiSnapshotText);
        AssertContains("type Samples.GeneratedInterop.Notifier", abiSnapshotText);
        AssertContains("  constructor Notifier(string seed)", abiSnapshotText);
        AssertContains("  field readonly string Name", abiSnapshotText);
        AssertContains("  field static readonly string Kind", abiSnapshotText);
        AssertContains("  field int Count", abiSnapshotText);
        AssertContains("  field static string MutableKind", abiSnapshotText);
        AssertContains("  property get string DisplayName", abiSnapshotText);
        AssertContains("  property get set string DisplayCode", abiSnapshotText);
        AssertContains("  property static get string Build", abiSnapshotText);
        AssertContains("  property static get set string Channel", abiSnapshotText);
        AssertContains("  event add remove Samples.GeneratedInterop.ChangedHandler Changed", abiSnapshotText);
        AssertContains("  event static add remove Samples.GeneratedInterop.ChangedHandler GlobalChanged", abiSnapshotText);
        AssertContains("  method string Echo(string value)", abiSnapshotText);
        AssertContains("  method static string StaticEcho(string value)", abiSnapshotText);
        AssertContains("type Samples.GeneratedInterop.IListener", abiSnapshotText);
        AssertContains("  event add remove Samples.GeneratedInterop.ChangedHandler Changed", abiSnapshotText);
        AssertContains("  method string Echo(string value)", abiSnapshotText);
        var generatedMetadata = metadata.Assemblies.Single();
        var notifierType = Require(
            generatedMetadata.Types.SingleOrDefault(type => string.Equals(type.FullName, "Samples.GeneratedInterop.Notifier", StringComparison.Ordinal)),
            "Generated Notifier metadata should be present.");
        var changedEvent = Require(
            notifierType.Events.SingleOrDefault(eventSymbol => string.Equals(eventSymbol.Name, "Changed", StringComparison.Ordinal)),
            "Generated Notifier instance event metadata should be present.");
        AssertEqual("Samples.GeneratedInterop.ChangedHandler", changedEvent.Type);
        AssertFalse(changedEvent.IsStatic, "Generated Notifier.Changed event should be instance metadata.");
        AssertTrue(changedEvent.HasPublicAdder, "Generated Notifier.Changed event should expose a public add accessor.");
        AssertTrue(changedEvent.HasPublicRemover, "Generated Notifier.Changed event should expose a public remove accessor.");

        var globalChangedEvent = Require(
            notifierType.Events.SingleOrDefault(eventSymbol => string.Equals(eventSymbol.Name, "GlobalChanged", StringComparison.Ordinal)),
            "Generated Notifier static event metadata should be present.");
        AssertEqual("Samples.GeneratedInterop.ChangedHandler", globalChangedEvent.Type);
        AssertTrue(globalChangedEvent.IsStatic, "Generated Notifier.GlobalChanged event should be static metadata.");
        AssertTrue(globalChangedEvent.HasPublicAdder, "Generated Notifier.GlobalChanged event should expose a public add accessor.");
        AssertTrue(globalChangedEvent.HasPublicRemover, "Generated Notifier.GlobalChanged event should expose a public remove accessor.");

        var listenerType = Require(
            generatedMetadata.Types.SingleOrDefault(type => string.Equals(type.FullName, "Samples.GeneratedInterop.IListener", StringComparison.Ordinal)),
            "Generated IListener metadata should be present.");
        var listenerChangedEvent = Require(
            listenerType.Events.SingleOrDefault(eventSymbol => string.Equals(eventSymbol.Name, "Changed", StringComparison.Ordinal)),
            "Generated IListener event metadata should be present.");
        AssertEqual("Samples.GeneratedInterop.ChangedHandler", listenerChangedEvent.Type);
        AssertFalse(listenerChangedEvent.IsStatic, "Generated IListener.Changed event should be instance metadata.");
        AssertTrue(listenerChangedEvent.HasPublicAdder, "Generated IListener.Changed event should expose a public add accessor.");
        AssertTrue(listenerChangedEvent.HasPublicRemover, "Generated IListener.Changed event should expose a public remove accessor.");

        var consumerRoot = Path.Combine(root, "Consumer");
        Directory.CreateDirectory(consumerRoot);
        WriteFile(consumerRoot, "ConsumerSmoke.csproj", """
            <Project Sdk="Microsoft.NET.Sdk">
              <PropertyGroup>
                <TargetFramework>net48</TargetFramework>
                <LangVersion>7.3</LangVersion>
                <ImplicitUsings>false</ImplicitUsings>
                <Nullable>disable</Nullable>
                <AssemblyName>ConsumerSmoke</AssemblyName>
              </PropertyGroup>
              <ItemGroup>
                <Reference Include="InteropSource">
                  <HintPath>../generated/bin/Debug/net48/InteropSource.dll</HintPath>
                </Reference>
              </ItemGroup>
            </Project>
            """);
        WriteFile(consumerRoot, "NuGet.config", """
            <?xml version="1.0" encoding="utf-8"?>
            <configuration>
              <packageSources>
                <clear />
              </packageSources>
            </configuration>
            """);
        WriteFile(consumerRoot, "Consumer.cs", """
            using System;

            namespace ConsumerSmoke
            {
                public static class Consumer
                {
                    private sealed class Listener : Samples.GeneratedInterop.IListener
                    {
                        public event Samples.GeneratedInterop.ChangedHandler Changed;

                        public string Echo(string value)
                        {
                            return value;
                        }
                    }

                    public static string CallTypeSharp()
                    {
                        var delegateAttribute = (ObsoleteAttribute)Attribute.GetCustomAttribute(
                            typeof(Samples.GeneratedInterop.Transform),
                            typeof(ObsoleteAttribute));
                        var transform = new Samples.GeneratedInterop.Transform(value => value + " from C#");
                        var joiner = new Samples.GeneratedInterop.Joiner((separator, values) => string.Join(separator, values));
                        var notifier = new Samples.GeneratedInterop.Notifier("seed");
                        Samples.GeneratedInterop.Notifier.GlobalChanged += value => { };
                        notifier.Changed += value => { };
                        Samples.GeneratedInterop.IListener listener = new Listener();
                        listener.Changed += value => { };
                        notifier.DisplayCode = notifier.DisplayCode + ":updated";
                        notifier.Count = notifier.Count + 1;
                        Samples.GeneratedInterop.Notifier.Channel = Samples.GeneratedInterop.Notifier.Channel + ":updated";
                        Samples.GeneratedInterop.Notifier.MutableKind = Samples.GeneratedInterop.Notifier.MutableKind + ":updated";
                        return delegateAttribute.Message + ":" + joiner("|", "a", "b") + ":" + transform(notifier.Echo(notifier.Name + notifier.DisplayName + notifier.DisplayCode + notifier.Count.ToString() + Samples.GeneratedInterop.Notifier.Kind + Samples.GeneratedInterop.Notifier.Build + Samples.GeneratedInterop.Notifier.Channel + Samples.GeneratedInterop.Notifier.MutableKind + Samples.GeneratedInterop.Notifier.StaticEcho(Samples.GeneratedInterop.Module.greeting())));
                    }
                }
            }
            """);

        var build = RunProcess("dotnet", "build ConsumerSmoke.csproj --nologo --verbosity quiet --ignore-failed-sources", consumerRoot);

        AssertTrue(
            build.ExitCode == 0,
            $"C# net48 consumer project should compile against the generated TypeSharp assembly.\nSTDOUT:\n{build.StandardOutput}\nSTDERR:\n{build.StandardError}");
    });
}

static void CompilerCheckPerformanceSmokeStaysBounded()
{
    WithWorkspace(root =>
    {
        var manifestPath = WriteManifest(root, """
            [project]
            name = "PerformanceSmoke"
            targetFramework = "net48"
            outputType = "library"
            rootNamespace = "Samples.Performance"
            generatedOutputRoot = "generated"
            """);

        const int sourceFileCount = 80;
        const int functionsPerFile = 15;
        var builder = new StringBuilder();
        for (var fileIndex = 0; fileIndex < sourceFileCount; fileIndex++)
        {
            builder.Clear();
            builder.AppendLine("namespace Samples.Performance");
            builder.AppendLine();

            for (var functionIndex = 0; functionIndex < functionsPerFile; functionIndex++)
            {
                var value = fileIndex * functionsPerFile + functionIndex;
                builder.AppendLine($"export fun value{value}(): int = {value}");
            }

            WriteFile(root, $"src/File{fileIndex:000}.tysh", builder.ToString());
        }

        var stopwatch = Stopwatch.StartNew();
        var result = TypeSharpChecker.Check(manifestPath);
        stopwatch.Stop();

        AssertEqual(sourceFileCount, result.SourceFiles.Count);
        AssertEqual(0, result.Diagnostics.Count);
        AssertTrue(
            stopwatch.Elapsed < TimeSpan.FromSeconds(15),
            $"Compiler check performance smoke exceeded 15 seconds: {stopwatch.Elapsed.TotalMilliseconds:0}ms.");
    });
}

static void CompilerCheckKeepsParallelDiagnosticsInSourceOrder()
{
    WithWorkspace(root =>
    {
        var manifestPath = WriteManifest(root, """
            [project]
            name = "ParallelDiagnostics"
            targetFramework = "net48"
            outputType = "library"
            rootNamespace = "Samples.ParallelDiagnostics"
            generatedOutputRoot = "generated"
            """);

        WriteFile(root, "src/Zeta.tysh", """
            namespace Samples.ParallelDiagnostics

            export fun zeta(): string = 1
            """);
        WriteFile(root, "src/Alpha.tysh", """
            namespace Samples.ParallelDiagnostics

            export fun alpha(): string = 2
            """);

        var result = TypeSharpChecker.Check(manifestPath);
        var diagnostics = result.Diagnostics.Where(diagnostic => diagnostic.Code == "TS2228").ToArray();

        AssertEqual(2, diagnostics.Length);
        AssertEqual("src/Alpha.tysh", diagnostics[0].File);
        AssertEqual("src/Zeta.tysh", diagnostics[1].File);
    });
}

static void Net48ApplicationModelHostsReferenceGeneratedAssemblyAndRuntime()
{
    WithWorkspace(root =>
    {
        var manifestPath = WriteManifest(root, """
            [project]
            name = "HostInteropSource"
            targetFramework = "net48"
            outputType = "library"
            rootNamespace = "Samples.HostInterop"
            generatedOutputRoot = "generated"
            """);
        WriteFile(root, "src/Main.tysh", """
            namespace Samples.HostInterop

            export fun greeting(): string = "Hello from TypeSharp"
            """);
        using var output = new StringWriter();
        using var error = new StringWriter();

        var exitCode = TypeSharpCli.Run(["build", manifestPath], output, error);

        AssertEqual(0, exitCode);
        AssertEqual(string.Empty, error.ToString());
        AssertContains("Generated assembly: bin/Debug/net48/HostInteropSource.dll", output.ToString());

        var generatedAssemblyPath = Path.Combine(root, "generated", "bin", "Debug", "net48", "HostInteropSource.dll");
        AssertTrue(File.Exists(generatedAssemblyPath), "TypeSharp build should produce a generated assembly for host compatibility smokes.");

        var coreAssemblyPath = BuildRepositoryAssembly(
            "lang/TypeSharp.Core/TypeSharp.Core.csproj",
            "lang/TypeSharp.Core/bin/Debug/net48/TypeSharp.Core.dll");
        var runtimeAssemblyPath = BuildRepositoryAssembly(
            "lang/TypeSharp.Runtime/TypeSharp.Runtime.csproj",
            "lang/TypeSharp.Runtime/bin/Debug/net48/TypeSharp.Runtime.dll");

        BuildApplicationModelHostProject(
            root,
            "AspNetWebFormsHostSmoke",
            ["System.Web"],
            generatedAssemblyPath,
            coreAssemblyPath,
            runtimeAssemblyPath,
            """
            using System.Web.UI;

            namespace AspNetWebFormsHostSmoke
            {
                public sealed class HomePage : Page
                {
                    public string RenderGreeting()
                    {
                        var unit = TypeSharp.Core.Unit.Value;
                        return Samples.HostInterop.Module.greeting()
                            + ":"
                            + TypeSharp.Runtime.TypeSharpRuntimeInfo.TargetFramework
                            + ":"
                            + unit.ToString();
                    }
                }
            }
            """);

        BuildApplicationModelHostProject(
            root,
            "WcfContractHostSmoke",
            ["System.ServiceModel"],
            generatedAssemblyPath,
            coreAssemblyPath,
            runtimeAssemblyPath,
            """
            using System.ServiceModel;

            namespace WcfContractHostSmoke
            {
                [ServiceContract]
                public interface IGreetingService
                {
                    [OperationContract]
                    string GetGreeting();
                }

                public sealed class GreetingService : IGreetingService
                {
                    public string GetGreeting()
                    {
                        var option = TypeSharp.Core.Option<string>.Some(Samples.HostInterop.Module.greeting());
                        return option.Value + ":" + TypeSharp.Runtime.TypeSharpRuntimeInfo.TargetFramework;
                    }
                }
            }
            """);

        BuildApplicationModelHostProject(
            root,
            "WorkerServiceHostSmoke",
            ["System.ServiceProcess"],
            generatedAssemblyPath,
            coreAssemblyPath,
            runtimeAssemblyPath,
            """
            using System.ServiceProcess;

            namespace WorkerServiceHostSmoke
            {
                public sealed class GreetingWorker : ServiceBase
                {
                    public string RunOnce()
                    {
                        var result = TypeSharp.Core.Result<string, string>.Ok(Samples.HostInterop.Module.greeting());
                        return result.Value + ":" + TypeSharp.Runtime.TypeSharpRuntimeInfo.RuntimeAbiVersion.ToString();
                    }
                }
            }
            """);
    });
}

static void CliBuildStopsBeforeEmissionOnDiagnostics()
{
    WithWorkspace(root =>
    {
        var manifestPath = WriteManifest(root, """
            [project]
            name = "BuildDiagnostics"
            generatedOutputRoot = "generated"
            """);
        WriteFile(root, "src/Main.tysh", """
            namespace Samples.BuildDiagnostics

            export fun broken(): string
            """);
        using var output = new StringWriter();
        using var error = new StringWriter();

        var exitCode = TypeSharpCli.Run(["build", manifestPath, "--diagnostic-format", "json"], output, error);

        AssertEqual(1, exitCode);
        AssertEqual(string.Empty, output.ToString());
        AssertContains("\"code\": \"TS1001\"", error.ToString());
        AssertFalse(File.Exists(Path.Combine(root, "generated", "src", "Main.g.cs")), "Build should not emit generated C# when diagnostics contain errors.");
        AssertFalse(File.Exists(Path.Combine(root, "generated", "BuildDiagnostics.Generated.csproj")), "Build should not emit generated C# project when diagnostics contain errors.");
        AssertFalse(File.Exists(Path.Combine(root, "generated", "bin", "Debug", "net48", "BuildDiagnostics.dll")), "Build should not emit generated assembly when diagnostics contain errors.");
    });
}

static void AssertEqual<T>(T expected, T actual)
{
    if (!EqualityComparer<T>.Default.Equals(expected, actual))
    {
        throw new InvalidOperationException($"Expected '{expected}', got '{actual}'.");
    }
}

static void AssertSequence<T>(IReadOnlyList<T> expected, IReadOnlyList<T> actual)
{
    AssertEqual(expected.Count, actual.Count);
    for (var index = 0; index < expected.Count; index++)
    {
        AssertEqual(expected[index], actual[index]);
    }
}

static void AssertTrue(bool value, string message)
{
    if (!value)
    {
        throw new InvalidOperationException(message);
    }
}

static void AssertFalse(bool value, string message) => AssertTrue(!value, message);

static void AssertContains(string expectedSubstring, string actual)
{
    if (!actual.Contains(expectedSubstring, StringComparison.Ordinal))
    {
        var normalizedExpected = NormalizeTestLineEndings(expectedSubstring);
        var normalizedActual = NormalizeTestLineEndings(actual);
        if (!normalizedActual.Contains(normalizedExpected, StringComparison.Ordinal))
        {
            throw new InvalidOperationException($"Expected output to contain '{expectedSubstring}', got '{actual}'.");
        }
    }
}

static string NormalizeTestLineEndings(string value) =>
    value.Replace("\r\n", "\n", StringComparison.Ordinal).Replace('\r', '\n');

static IReadOnlyList<string> ExtractAstroSidebarPublicRoutes(string astroConfig)
{
    var routes = Regex
        .Matches(astroConfig, "slug: '([^']+)'")
        .Select(match => match.Groups[1].Value == "index" ? "/" : $"/{match.Groups[1].Value}/")
        .ToArray();

    AssertTrue(routes.Length > 0, "Astro sidebar should expose public docs routes.");
    AssertEqual(routes.Length, routes.Distinct(StringComparer.Ordinal).Count());
    return routes;
}

static void AssertRenderedVerifierCoversSidebarPublicRoutes(IReadOnlyList<string> sidebarPublicRoutes, string renderedVerifier)
{
    foreach (var route in sidebarPublicRoutes)
    {
        var renderedPath = route == "/" ? "dist/index.html" : $"dist/{route.Trim('/')}/index.html";
        AssertTrue(
            renderedVerifier.Contains($"fs.readFileSync('{renderedPath}', 'utf8')", StringComparison.Ordinal),
            $"Rendered verifier must read the sidebar public docs route '{route}'.");
        AssertTrue(
            renderedVerifier.Contains($"'{route}'", StringComparison.Ordinal),
            $"Rendered verifier publicPageRoutes must include the sidebar public docs route '{route}'.");
    }
}

static void AssertWorkflowRouteTableCoversSidebarPublicRoutes(IReadOnlyList<string> sidebarPublicRoutes, string workflow, string workflowLabel)
{
    foreach (var route in sidebarPublicRoutes)
    {
        AssertTrue(
            workflow.Contains($"Path = '{route}'", StringComparison.Ordinal),
            $"{workflowLabel} route table must include the sidebar public docs route '{route}'.");
    }
}

static void AssertJsonDiagnostic(string json, string code, string severity, string messageSubstring)
{
    using var document = JsonDocument.Parse(json);
    var diagnostics = document.RootElement.GetProperty("diagnostics").EnumerateArray();
    foreach (var diagnostic in diagnostics)
    {
        if (diagnostic.GetProperty("code").GetString() != code)
        {
            continue;
        }

        AssertEqual(severity, diagnostic.GetProperty("severity").GetString());
        AssertContains(messageSubstring, diagnostic.GetProperty("message").GetString() ?? string.Empty);
        return;
    }

    throw new InvalidOperationException($"Expected JSON diagnostics to contain '{code}', got '{json}'.");
}

static void AssertDiagnosticDescriptorJson(string json, string code, string title, string severity, string category)
{
    using var document = JsonDocument.Parse(json);
    var diagnostic = document.RootElement.GetProperty("diagnostic");
    AssertEqual(code, diagnostic.GetProperty("code").GetString());
    AssertEqual(title, diagnostic.GetProperty("title").GetString());
    AssertEqual(severity, diagnostic.GetProperty("severity").GetString());
    AssertEqual(category, diagnostic.GetProperty("category").GetString());
    AssertFalse(string.IsNullOrWhiteSpace(diagnostic.GetProperty("explanation").GetString()), "Diagnostic descriptor JSON should include an explanation.");
    AssertFalse(string.IsNullOrWhiteSpace(diagnostic.GetProperty("suggestedAction").GetString()), "Diagnostic descriptor JSON should include a suggested action.");
}

static void AssertContainsBefore(string actual, string earlierSubstring, string laterSubstring)
{
    var earlierIndex = actual.IndexOf(earlierSubstring, StringComparison.Ordinal);
    var laterIndex = actual.IndexOf(laterSubstring, StringComparison.Ordinal);
    if (earlierIndex < 0 || laterIndex < 0)
    {
        var normalizedActual = NormalizeTestLineEndings(actual);
        earlierIndex = normalizedActual.IndexOf(NormalizeTestLineEndings(earlierSubstring), StringComparison.Ordinal);
        laterIndex = normalizedActual.IndexOf(NormalizeTestLineEndings(laterSubstring), StringComparison.Ordinal);
    }

    AssertTrue(earlierIndex >= 0, $"Expected output to contain '{earlierSubstring}'.");
    AssertTrue(laterIndex >= 0, $"Expected output to contain '{laterSubstring}'.");
    AssertTrue(
        earlierIndex < laterIndex,
        $"Expected '{earlierSubstring}' to appear before '{laterSubstring}'.");
}

static void AssertReleaseInstallRouteUsesWorkflowAssetNames(
    string releaseWorkflow,
    IReadOnlyDictionary<string, string> publicInstallPages,
    IReadOnlyDictionary<string, string> runtimeOnlyPages,
    IReadOnlyDictionary<string, string> vsixPages,
    string installPage)
{
    var workflowAssets = Regex.Matches(
            releaseWorkflow,
            @"typesharp-(?:cli-dotnet|runtime-net48)-\$tag\.zip")
        .Cast<Match>()
        .Select(match => match.Value)
        .Distinct(StringComparer.Ordinal)
        .OrderBy(value => value, StringComparer.Ordinal)
        .ToArray();

    AssertSequence(
        new[] { "typesharp-cli-dotnet-$tag.zip", "typesharp-runtime-net48-$tag.zip" },
        workflowAssets);

    var workflowVsixAssets = Regex.Matches(
            releaseWorkflow,
            @"typesharp-vscode-\$tag\.vsix")
        .Cast<Match>()
        .Select(match => match.Value)
        .Distinct(StringComparer.Ordinal)
        .OrderBy(value => value, StringComparer.Ordinal)
        .ToArray();

    AssertSequence(
        new[] { "typesharp-vscode-$tag.vsix" },
        workflowVsixAssets);

    var cliPublicAsset = workflowAssets[0].Replace("$tag", "<tag>");
    var runtimePublicAsset = workflowAssets[1].Replace("$tag", "<tag>");
    var vsixPublicAsset = workflowVsixAssets[0].Replace("$tag", "<tag>");
    var cliInstallAsset = workflowAssets[0].Replace("$tag", "$version");
    var runtimeInstallAsset = workflowAssets[1].Replace("$tag", "$version");
    var vsixInstallAsset = workflowVsixAssets[0].Replace("$tag", "$version");

    foreach (var page in publicInstallPages)
    {
        AssertContains(cliPublicAsset, page.Value);
        AssertContains(runtimePublicAsset, page.Value);
        AssertContains("SHA256SUMS.txt", page.Value);
    }

    foreach (var page in runtimeOnlyPages)
    {
        AssertContains(runtimePublicAsset, page.Value);
        AssertContains("SHA256SUMS.txt", page.Value);
    }

    foreach (var page in vsixPages)
    {
        AssertContains(vsixPublicAsset, page.Value);
        AssertContains("SHA256SUMS.txt", page.Value);
    }

    AssertContains($"Invoke-WebRequest \"$release/{cliInstallAsset}\"", installPage);
    AssertContains($"Invoke-WebRequest \"$release/{runtimeInstallAsset}\"", installPage);
    AssertContains($"Assert-ReleaseAssetHash \"{cliInstallAsset}\"", installPage);
    AssertContains($"Assert-ReleaseAssetHash \"{runtimeInstallAsset}\"", installPage);

    AssertContains($"Invoke-WebRequest \"$release/{vsixInstallAsset}\"", vsixPages["VS Code And LSP"]);
    AssertContains($"Assert-ReleaseAssetHash \"{vsixInstallAsset}\"", vsixPages["VS Code And LSP"]);
}

static bool IsDocsOwnedSourcePath(string siteRoot, string path)
{
    var relativePath = Path.GetRelativePath(siteRoot, path);
    var segments = relativePath.Split(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
    if (segments.Length == 0)
    {
        return false;
    }

    var firstSegment = segments[0];
    return !string.Equals(firstSegment, ".astro", StringComparison.OrdinalIgnoreCase)
        && !string.Equals(firstSegment, "dist", StringComparison.OrdinalIgnoreCase)
        && !string.Equals(firstSegment, "node_modules", StringComparison.OrdinalIgnoreCase);
}

static bool IsJavaScriptSourcePath(string path)
{
    var extension = Path.GetExtension(path);
    return string.Equals(extension, ".js", StringComparison.OrdinalIgnoreCase)
        || string.Equals(extension, ".mjs", StringComparison.OrdinalIgnoreCase)
        || string.Equals(extension, ".cjs", StringComparison.OrdinalIgnoreCase)
        || string.Equals(extension, ".jsx", StringComparison.OrdinalIgnoreCase)
        || string.Equals(extension, ".mjsx", StringComparison.OrdinalIgnoreCase);
}

static int CountOccurrences(string text, string value)
{
    var count = 0;
    var index = 0;
    while ((index = text.IndexOf(value, index, StringComparison.Ordinal)) >= 0)
    {
        count++;
        index += value.Length;
    }

    return count;
}

static void AssertDocsTextFencesDoNotContainTypeSharpSource(string docsContentRoot, IReadOnlyList<string> markdownPaths)
{
    var violations = new List<string>();
    foreach (var markdownPath in markdownPaths)
    {
        var text = File.ReadAllText(markdownPath);
        foreach (var block in EnumerateMarkdownCodeBlocks(text))
        {
            if (string.Equals(block.Language, "text", StringComparison.Ordinal)
                && LooksLikeTypeSharpSourceBlock(block.Body))
            {
                var relativePath = Path.GetRelativePath(docsContentRoot, markdownPath).Replace('\\', '/');
                violations.Add($"{relativePath}:{block.StartLine}");
            }
        }
    }

    AssertEqual(string.Empty, string.Join(Environment.NewLine, violations));
}

static IEnumerable<(string Language, string Body, int StartLine)> EnumerateMarkdownCodeBlocks(string text)
{
    var normalized = text.Replace("\r\n", "\n", StringComparison.Ordinal).Replace('\r', '\n');
    var lines = normalized.Split('\n');
    var body = new StringBuilder();
    var inFence = false;
    var language = string.Empty;
    var startLine = 0;

    for (var index = 0; index < lines.Length; index++)
    {
        var line = lines[index];
        if (!inFence)
        {
            if (!line.StartsWith("```", StringComparison.Ordinal))
            {
                continue;
            }

            language = line.Substring(3).Trim();
            var languageSuffix = language.IndexOf(' ');
            if (languageSuffix >= 0)
            {
                language = language.Substring(0, languageSuffix);
            }

            body.Clear();
            inFence = true;
            startLine = index + 1;
            continue;
        }

        if (line.StartsWith("```", StringComparison.Ordinal))
        {
            yield return (language, body.ToString(), startLine);
            inFence = false;
            language = string.Empty;
            continue;
        }

        body.AppendLine(line);
    }
}

static bool LooksLikeTypeSharpSourceBlock(string body)
{
    var firstLine = body
        .Replace("\r\n", "\n", StringComparison.Ordinal)
        .Replace('\r', '\n')
        .Split('\n')
        .Select(line => line.Trim())
        .FirstOrDefault(line => line.Length > 0);
    if (firstLine is null)
    {
        return false;
    }

    return StartsWithTypeSharpKeyword(firstLine, "namespace")
        || StartsWithTypeSharpKeyword(firstLine, "import")
        || firstLine.StartsWith("public union ", StringComparison.Ordinal)
        || StartsWithTypeSharpKeyword(firstLine, "export")
        || StartsWithTypeSharpKeyword(firstLine, "let")
        || StartsWithTypeSharpKeyword(firstLine, "type")
        || StartsWithTypeSharpKeyword(firstLine, "record")
        || StartsWithTypeSharpKeyword(firstLine, "fun")
        || StartsWithTypeSharpKeyword(firstLine, "literal")
        || firstLine.StartsWith("value |>", StringComparison.Ordinal)
        || firstLine.StartsWith("g(f(", StringComparison.Ordinal);
}

static bool StartsWithTypeSharpKeyword(string line, string keyword)
{
    return string.Equals(line, keyword, StringComparison.Ordinal)
        || line.StartsWith(keyword + " ", StringComparison.Ordinal)
        || line.StartsWith(keyword + "\t", StringComparison.Ordinal);
}

static void AssertThrows<TException>(Action action)
    where TException : Exception
{
    try
    {
        action();
    }
    catch (TException)
    {
        return;
    }
    catch (Exception ex)
    {
        throw new InvalidOperationException($"Expected {typeof(TException).Name}, got {ex.GetType().Name}.");
    }

    throw new InvalidOperationException($"Expected {typeof(TException).Name}.");
}

static void AssertTextFileEquals(string path, string actual)
{
    var expected = File.ReadAllText(path).Replace("\r\n", "\n", StringComparison.Ordinal);
    AssertTextEquals(expected, actual);
}

static void AssertTextEquals(string expected, string actual)
{
    expected = expected.Replace("\r\n", "\n", StringComparison.Ordinal);
    actual = actual.Replace("\r\n", "\n", StringComparison.Ordinal);
    if (!string.Equals(expected, actual, StringComparison.Ordinal))
    {
        throw new InvalidOperationException($"Text mismatch.\nExpected:\n{expected}\nActual:\n{actual}");
    }
}

static void AssertNet48PackageFreeArtifact(string projectPath)
{
    var project = XDocument.Load(projectPath);
    var targetFrameworks = project.Descendants()
        .Where(element => element.Name.LocalName is "TargetFramework" or "TargetFrameworks")
        .Select(element => element.Value.Trim())
        .ToArray();

    AssertEqual(1, targetFrameworks.Length);
    AssertEqual("net48", targetFrameworks[0]);
    AssertFalse(
        project.Descendants().Any(element => element.Name.LocalName == "PackageReference"),
        $"{projectPath} should not use external NuGet package references.");

    var packagesConfig = Path.Combine(Path.GetDirectoryName(projectPath) ?? string.Empty, "packages.config");
    AssertFalse(File.Exists(packagesConfig), $"{projectPath} should not use packages.config.");
}

static void AssertNoDisallowedNet5RuntimeApiReferences(string sourceRoot)
{
    var disallowed = new[]
    {
        "System.Text.Json",
        "DateOnly",
        "TimeOnly",
        "System.Half",
        "System.Index",
        "System.Range",
        "Span<",
        "ReadOnlySpan<",
        "Memory<",
        "ReadOnlyMemory<",
        "ValueTask",
        "IAsyncEnumerable",
        "IAsyncEnumerator",
        "Parallel.ForEachAsync",
        "Task.WaitAsync"
    };

    foreach (var sourceFile in Directory.EnumerateFiles(sourceRoot, "*.cs", SearchOption.AllDirectories))
    {
        var text = File.ReadAllText(sourceFile);
        foreach (var api in disallowed)
        {
            AssertFalse(
                text.Contains(api, StringComparison.Ordinal),
                $"{sourceFile} should not reference .NET 5+ or package-backed runtime API '{api}'.");
        }
    }
}

static T Require<T>(T? value, string message)
    where T : class
{
    if (value is null)
    {
        throw new InvalidOperationException(message);
    }

    return value;
}

static void WithWorkspace(Action<string> action)
{
    var root = Path.Combine(Directory.GetCurrentDirectory(), "test", "tmp", Guid.NewGuid().ToString("N"));
    Directory.CreateDirectory(root);

    try
    {
        action(root);
    }
    finally
    {
        if (Directory.Exists(root))
        {
            Directory.Delete(root, recursive: true);
        }
    }
}

static void CopyDirectory(string sourceRoot, string targetRoot)
{
    foreach (var directory in Directory.EnumerateDirectories(sourceRoot, "*", SearchOption.AllDirectories))
    {
        var relativeDirectory = Path.GetRelativePath(sourceRoot, directory);
        Directory.CreateDirectory(Path.Combine(targetRoot, relativeDirectory));
    }

    Directory.CreateDirectory(targetRoot);
    foreach (var file in Directory.EnumerateFiles(sourceRoot, "*", SearchOption.AllDirectories))
    {
        var relativeFile = Path.GetRelativePath(sourceRoot, file);
        var targetFile = Path.Combine(targetRoot, relativeFile);
        Directory.CreateDirectory(Path.GetDirectoryName(targetFile) ?? targetRoot);
        File.Copy(file, targetFile, overwrite: true);
    }
}

static string WriteManifest(string root, string content)
{
    var manifestPath = Path.Combine(root, TypeSharpManifestLocator.ManifestFileName);
    File.WriteAllText(manifestPath, content.Replace("\r\n", "\n", StringComparison.Ordinal));
    return manifestPath;
}

static void WriteFile(string root, string relativePath, string content)
{
    var path = Path.Combine(root, relativePath.Replace('/', Path.DirectorySeparatorChar));
    Directory.CreateDirectory(Path.GetDirectoryName(path) ?? root);
    File.WriteAllText(path, content);
}

static void WriteLspFrame(Stream stream, string json)
{
    var payload = Encoding.UTF8.GetBytes(json);
    var header = Encoding.ASCII.GetBytes($"Content-Length: {payload.Length}\r\n\r\n");
    stream.Write(header, 0, header.Length);
    stream.Write(payload, 0, payload.Length);
}

static void BuildLegacyReferenceDll(string root, string assemblyName)
{
    var projectFile = $$"""
        <Project Sdk="Microsoft.NET.Sdk">
          <PropertyGroup>
            <TargetFramework>net48</TargetFramework>
            <LangVersion>7.3</LangVersion>
            <ImplicitUsings>false</ImplicitUsings>
            <Nullable>disable</Nullable>
            <AssemblyName>{{assemblyName}}</AssemblyName>
          </PropertyGroup>
        </Project>
        """;
    var nugetConfig = """
        <?xml version="1.0" encoding="utf-8"?>
        <configuration>
          <packageSources>
            <clear />
          </packageSources>
        </configuration>
        """;
    var source = """
        using System.Runtime.CompilerServices;

        namespace Legacy.Tools
        {
            public static class LegacyApi
            {
                public static string Echo(string value)
                {
                    return value;
                }
            }

            public enum LegacyColor : byte
            {
                Red = 1,
                Green = 2,
                Blue = 4
            }

            public static class LegacyParams
            {
                public static string Join(string separator, params string[] values)
                {
                    return string.Join(separator, values);
                }
            }

            public static class LegacyByRef
            {
                public static bool TryParseCount(string text, out int value)
                {
                    return int.TryParse(text, out value);
